function expectedContentInterfaceKeys(interfaceName) {
  const interfaceSpec = EXPECTED_CONTENT_INTERFACES.find((spec) => spec.name === interfaceName);
  return interfaceSpec ? interfaceSpec.fields.map((field) => field.name) : [];
}
