function resolveLocalModule(fromFilePath, request) {
  const base = path.resolve(path.dirname(fromFilePath), request);
  const candidates = [base, `${base}.ts`, `${base}.tsx`, `${base}.js`, path.join(base, 'index.ts')];
  const found = candidates.find(
    (candidate) => fs.existsSync(candidate) && fs.statSync(candidate).isFile(),
  );
  if (!found) throw new Error(`Cannot resolve ${request} from ${fromFilePath}`);
  return found;
}

function loadTs(relativePath, exportName) {
  const filePath = path.resolve(repoRoot, relativePath);
  if (moduleCache.has(filePath)) {
    const cached = moduleCache.get(filePath);
    return exportName ? cached[exportName] : cached;
  }

  const source = fs.readFileSync(filePath, 'utf8');
  const output = ts.transpileModule(source, {
    compilerOptions: {
      module: ts.ModuleKind.CommonJS,
      target: ts.ScriptTarget.ES2020,
    },
  }).outputText;
  const mod = { exports: {} };
  moduleCache.set(filePath, mod.exports);

  function localRequire(request) {
    if (request === 'expo-speech') {
      return speechMock;
    }
    if (request.startsWith('.')) {
      const resolvedPath = resolveLocalModule(filePath, request);
      const relativeResolvedPath = path.relative(repoRoot, resolvedPath);
      return loadTs(relativeResolvedPath);
    }
    return require(request);
  }

  new Function('module', 'exports', 'require', output)(mod, mod.exports, localRequire);
  moduleCache.set(filePath, mod.exports);
  return exportName ? mod.exports[exportName] : mod.exports;
}

function loadJson(relativePath) {
  return JSON.parse(fs.readFileSync(path.resolve(repoRoot, relativePath), 'utf8'));
}

function loadText(relativePath) {
  return fs.readFileSync(path.resolve(repoRoot, relativePath), 'utf8');
}

function listSourceFiles(relativeDir) {
  const absoluteDir = path.resolve(repoRoot, relativeDir);
  const entries = fs.readdirSync(absoluteDir, { withFileTypes: true });

  return entries.flatMap((entry) => {
    const absolutePath = path.join(absoluteDir, entry.name);
    if (entry.isDirectory()) return listSourceFiles(path.relative(repoRoot, absolutePath));
    if (/\.[tj]sx?$/.test(entry.name)) return [absolutePath];
    return [];
  });
}

function loadStaticI18nExtras() {
  const sandbox = { window: {} };
  vm.createContext(sandbox);
  vm.runInContext(loadText('site/i18n-extras.js'), sandbox, { timeout: 3000 });
  return sandbox.window.__i18n_extra || {};
}

function fail(message) {
  failures.push(message);
}

function validateValidationScriptSyntax() {
  for (const relativePath of EXPECTED_VALIDATION_SCRIPT_SYNTAX_FILES) {
    const filePath = path.join(repoRoot, relativePath);
    try {
      new vm.Script(fs.readFileSync(filePath, 'utf8'), { filename: filePath });
      validationScriptSyntaxChecksValidated += 1;
    } catch (error) {
      fail(`${relativePath} must parse before validation runs: ${error.message}`);
    }
  }
}

function dateIsoDay(value) {
  return value instanceof Date && !Number.isNaN(value.getTime())
    ? value.toISOString().slice(0, 10)
    : '';
}

function validateStaticValidationSyntaxGate() {
  let valid = true;

  for (const fileName of STATIC_VALIDATION_SYNTAX_FILES) {
    const result = spawnSync(process.execPath, ['--check', fileName], {
      cwd: repoRoot,
      encoding: 'utf8',
    });
    if (result.status !== 0) {
      valid = false;
      fail(
        `${fileName} must parse before content validation runs:\n${(
          result.stderr ||
          result.stdout ||
          ''
        ).trim()}`,
      );
    } else {
      staticValidationSyntaxFilesValidated += 1;
    }
  }

  for (const check of STATIC_VALIDATION_IMPORT_CHECKS) {
    const result = spawnSync(process.execPath, ['-e', check.script], {
      cwd: repoRoot,
      encoding: 'utf8',
    });
    if (result.status !== 0) {
      valid = false;
      fail(
        `${check.label} must be importable before content validation runs:\n${(
          result.stderr ||
          result.stdout ||
          ''
        ).trim()}`,
      );
    } else {
      staticValidationImportChecksValidated += 1;
    }
  }

  if (valid) staticValidationSyntaxGateValidated = true;
}

function contentTestFileNames() {
  return fs
    .readdirSync(path.join(repoRoot, 'tests'))
    .filter((fileName) => /^content-.*\.test\.js$/.test(fileName))
    .map((fileName) => `tests/${fileName}`)
    .sort();
}

function validateContentTestValidateContentExecCwdGuard() {
  let total = 0;
  let pinned = 0;
  const unpinnedCalls = [];

  for (const fileName of contentTestFileNames()) {
    const source = fs.readFileSync(path.join(repoRoot, fileName), 'utf8');
    const calls = collectValidateContentExecFileSyncCalls(source);
    const summary = summarizePinnedCwdCalls(calls);
    total += summary.total;
    pinned += summary.pinned;

    calls.forEach((call) => {
      if (!call.hasPinnedCwd) {
        unpinnedCalls.push(`${fileName}:${sourceLineNumberForIndex(source, call.index)}`);
      }
    });
  }

  contentTestValidateContentExecCallsValidated = total;
  contentTestValidateContentExecCwdPinnedValidated = pinned;
  contentTestValidateContentExecCwdParityValidated = total > 0 && pinned === total;

  if (total === 0) {
    fail('content-test validate-content exec cwd guard found no direct validator exec calls');
  }
  if (!contentTestValidateContentExecCwdParityValidated) {
    fail(
      `content-test validate-content exec calls missing cwd: repoRoot: ${unpinnedCalls.join(', ')}`,
    );
  }
}

function validateStaticI18nArabicNaturalness() {
  const result = {
    requiredCopyValidated: 0,
    highFrequencyLabelsValidated: 0,
    forbiddenFragmentsValidated: 0,
    englishFallbacksValidated: 0,
  };
  const extra = loadStaticI18nExtras();
  const arabic = extra.ar;

  if (!arabic || typeof arabic !== 'object' || Array.isArray(arabic)) {
    fail('static Arabic i18n dictionary must exist');
    return result;
  }

  for (const [key, expected] of Object.entries(STATIC_I18N_ARABIC_EXPECTED_COPY)) {
    if (arabic[key] === expected) {
      result.requiredCopyValidated += 1;
    } else {
      fail(`Arabic static-site ${key} should use reviewed local copy`);
    }
  }

  for (const key of STATIC_I18N_ARABIC_HIGH_FREQUENCY_KEYS) {
    const value = arabic[key];
    if (typeof value === 'string' && value.trim()) {
      result.highFrequencyLabelsValidated += 1;
    } else {
      fail(`Arabic static-site ${key} must be a non-empty string`);
      continue;
    }

    const englishFallback = STATIC_I18N_ENGLISH_FALLBACKS_BY_KEY[key];
    if (!englishFallback) continue;
    if (new RegExp(escapeRegExp(englishFallback), 'i').test(value)) {
      fail(`Arabic static-site ${key} still uses English fallback`);
    } else {
      result.englishFallbacksValidated += 1;
    }
  }

  const serializedArabic = Object.values(arabic).join('\n');
  for (const fragment of STATIC_I18N_ARABIC_FORBIDDEN_FRAGMENTS) {
    if (new RegExp(escapeRegExp(fragment), 'i').test(serializedArabic)) {
      fail(`Arabic static-site dictionary still contains ${fragment}`);
    } else {
      result.forbiddenFragmentsValidated += 1;
    }
  }

  return result;
}

function exitWithValidationFailures() {
  if (failures.length === 0) return;
  console.error('Content validation failed:');
  for (const failure of failures) console.error(`- ${failure}`);
  process.exit(1);
}

function printValidationSummary(summary) {
  console.log('Content validation OK');
  console.log(JSON.stringify(summary, null, 2));
}

function finishFocusedValidation(summary) {
  exitWithValidationFailures();
  printValidationSummary(summary);
  process.exit(0);
}

function hasText(value) {
  return typeof value === 'string' && value.trim().length > 0;
}

function normalizeOptionText(value) {
  return typeof value === 'string' ? value.trim().replace(/\s+/g, ' ') : '';
}

function textIsTrimmedSingleSpaced(value) {
  return typeof value === 'string' && value === normalizeOptionText(value);
}

function normalizeComparableText(value) {
  return normalizeOptionText(value).toLocaleLowerCase('sv-SE');
}

function bilingualTextPairsAreDistinct(question) {
  return (
    normalizeComparableText(question.questionSv) !== normalizeComparableText(question.questionEn) &&
    normalizeComparableText(question.explanationSv) !==
      normalizeComparableText(question.explanationEn)
  );
}

function optionTextPairIsTranslatedOrInvariant(option) {
  const textSv = normalizeComparableText(option?.textSv);
  const textEn = normalizeComparableText(option?.textEn);
  if (!textSv || !textEn || textSv !== textEn) return true;

  const wordCount = normalizeOptionText(option.textSv).split(/\s+/).length;
  return wordCount <= 2;
}

function optionBilingualTextPairsAreValid(question) {
  if (!Array.isArray(question.options)) return false;
  return question.options.every(optionTextPairIsTranslatedOrInvariant);
}

function translationCompletenessParityIsValidated() {
  return (
    publishedQuestions > 0 &&
    questionBilingualTextPairsValidated === publishedQuestions &&
    questionOptionBilingualTextPairsValidated === publishedQuestions
  );
}

function translationNaturalnessGuardParityIsValidated() {
  return (
    publishedQuestions > 0 &&
    questionGeneratedTrueFalseNaturalnessValidated === publishedQuestions &&
    questionLuciaRoleEnglishNaturalnessValidated === publishedQuestions &&
    questionEuCooperationEnglishNaturalnessValidated === publishedQuestions &&
    questionOlderSickEnglishNaturalnessValidated === publishedQuestions &&
    questionCouncilOfEuropeWorkForEnglishNaturalnessValidated === publishedQuestions &&
    questionMayDayEnglishNaturalnessValidated === publishedQuestions &&
    questionPublicSectorEnglishNaturalnessValidated === publishedQuestions &&
    questionPublicServiceBroadcasterEnglishNaturalnessValidated === publishedQuestions &&
    questionLargestLakesEnglishNaturalnessValidated === publishedQuestions &&
    questionNationalMinoritiesEnglishNaturalnessValidated === publishedQuestions &&
    questionNewYearsEveDateEnglishNaturalnessValidated === publishedQuestions &&
    questionLuciaDayDateEnglishNaturalnessValidated === publishedQuestions &&
    questionRecordYearsEnglishNaturalnessValidated === publishedQuestions &&
    questionSaltsjobadenEnglishNaturalnessValidated === publishedQuestions &&
    questionSuffrage1921EnglishNaturalnessValidated === publishedQuestions &&
    questionLuciaExplanationRoleScaffoldValidated === publishedQuestions &&
    questionGoodFridayEnglishNaturalnessValidated === publishedQuestions &&
    questionReferendumAdvisorySwedishNaturalnessValidated === publishedQuestions &&
    questionSourceCriticismEnglishNaturalnessValidated === publishedQuestions &&
    questionRuleOfLawEnglishNaturalnessValidated === publishedQuestions * 3 &&
    questionReligiousFreedomParallelismValidated === publishedQuestions * 2 &&
    somaliGeographyNaturalnessParityValidated === true &&
    somaliHolidayFoodNaturalnessParityValidated === true
  );
}

function questionTextFieldsAreNormalized(question) {
  const fields = [
    question.questionSv,
    question.questionEn,
    question.explanationSv,
    question.explanationEn,
    question.uhrReference?.chapter,
    question.uhrReference?.section,
    ...(question.options || []).flatMap((option) => [option.textSv, option.textEn]),
  ];

  return fields.every(textIsTrimmedSingleSpaced);
}

function textHasSentenceEnding(value) {
  return typeof value === 'string' && /[.!?]$/.test(value.trim());
}

function validateStaticHeadMetadataParity() {
  const indexHtml = loadText('site/index.html');
  const titleIssues = findStaticHeadMetadataTitleIssues(indexHtml, 'site/index.html');
  const descriptionIssues = findStaticHeadMetadataDescriptionIssues(indexHtml, 'site/index.html');

  if (titleIssues.length > 0) {
    fail(
      `static head title must be branded, non-empty, and avoid pass/passport outcome copy:\n${formatUnsupportedStaticOutcomeSlogans(
        titleIssues,
      )}`,
    );
  } else {
    staticHeadMetadataTitleValidated = extractStaticHeadTitles(indexHtml).length;
  }

  if (descriptionIssues.length > 0) {
    fail(
      `static meta description must be non-empty and avoid pass/passport outcome copy:\n${formatUnsupportedStaticOutcomeSlogans(
        descriptionIssues,
      )}`,
    );
  } else {
    staticHeadMetadataDescriptionValidated = extractStaticHeadMetaDescriptions(indexHtml).length;
  }

  const expectedOutcomeClaimPatterns =
    UNSUPPORTED_STATIC_HEAD_TITLE_PATTERNS.length +
    UNSUPPORTED_STATIC_OUTCOME_SLOGAN_PATTERNS.length;
  if (titleIssues.length === 0 && descriptionIssues.length === 0) {
    staticHeadMetadataOutcomeClaimPatternsValidated = expectedOutcomeClaimPatterns;
  }
  staticHeadMetadataParityValidated =
    staticHeadMetadataTitleValidated > 0 &&
    staticHeadMetadataDescriptionValidated > 0 &&
    staticHeadMetadataOutcomeClaimPatternsValidated === expectedOutcomeClaimPatterns;
}

function validateStaticEbookOutcomeClaimPatterns() {
  const source = loadText('site/ebook.js');
  const offenders = STATIC_EBOOK_UNSUPPORTED_OUTCOME_CLAIM_PATTERNS.filter((pattern) =>
    pattern.test(source),
  );

  if (offenders.length > 0) {
    fail('static ebook contains unsupported pass-duration, pass-likelihood, or outcome copy');
  }

  return STATIC_EBOOK_UNSUPPORTED_OUTCOME_CLAIM_PATTERNS.length - offenders.length;
}

function validateStaticEbookPracticalTestClaims() {
  const source = loadText('site/ebook.js');
  let unsupportedPracticalClaimsValidated = 0;
  let sourceUrlsValidated = 0;
  let requiredCopyValidated = 0;

  STATIC_EBOOK_UNSUPPORTED_PRACTICAL_TEST_CLAIM_PATTERNS.forEach((pattern) => {
    if (pattern.test(source)) {
      fail(`static ebook contains unsupported practical test logistics claim: ${pattern}`);
      return;
    }
    unsupportedPracticalClaimsValidated += 1;
  });

  STATIC_EBOOK_PRACTICAL_TEST_SOURCE_URLS.forEach((url) => {
    if (!source.includes(url)) {
      fail(`static ebook practical test source metadata missing ${url}`);
      return;
    }
    sourceUrlsValidated += 1;
  });

  STATIC_EBOOK_PRACTICAL_TEST_REQUIRED_COPY.forEach((text) => {
    if (!source.includes(text)) {
      fail(`static ebook practical test copy missing current sourced claim: ${text}`);
      return;
    }
    requiredCopyValidated += 1;
  });

  return {
    requiredCopyValidated,
    sourceUrlsValidated,
    unsupportedPracticalClaimsValidated,
  };
}

function validateStaticEbookFactboxProvenance() {
  const source = loadText('site/ebook.js');
  let unsupportedFactboxClaimsValidated = 0;
  let sourceUrlsValidated = 0;
  let requiredCopyValidated = 0;
  let rawFactboxParagraphsValidated = 0;
  let rawFactboxParagraphsTotal = 0;

  STATIC_EBOOK_UNSUPPORTED_FACTBOX_PATTERNS.forEach((pattern) => {
    if (pattern.test(source)) {
      fail(`static ebook contains unsupported factbox or current prose claim: ${pattern}`);
      return;
    }
    unsupportedFactboxClaimsValidated += 1;
  });

  STATIC_EBOOK_FACTBOX_SOURCE_URLS.forEach((url) => {
    if (!source.includes(url)) {
      fail(`static ebook factbox source metadata missing ${url}`);
      return;
    }
    sourceUrlsValidated += 1;
  });

  STATIC_EBOOK_FACTBOX_REQUIRED_COPY.forEach((text) => {
    if (!source.includes(text)) {
      fail(`static ebook factbox provenance copy missing ${text}`);
      return;
    }
    requiredCopyValidated += 1;
  });

  Array.from(source.matchAll(/<div class="ebook__factbox">[\s\S]*?<p(?<attrs>[^>]*)>/g)).forEach(
    (match) => {
      rawFactboxParagraphsTotal += 1;
      const attrs = match.groups.attrs;
      if (!/ebookSourceKeyDataAttr\(|data-ebook-source-keys=/.test(attrs)) {
        fail(`static ebook raw factbox paragraph missing source metadata: ${match[0]}`);
        return;
      }
      rawFactboxParagraphsValidated += 1;
    },
  );

  return {
    rawFactboxParagraphsTotal,
    rawFactboxParagraphsValidated,
    requiredCopyValidated,
    sourceUrlsValidated,
    unsupportedFactboxClaimsValidated,
  };
}

function validateStaticEbookSourceAuthorityCopy() {
  const source = loadText('site/ebook.js');
  let patternsValidated = 0;

  STATIC_EBOOK_SOURCE_AUTHORITY_PHRASE_PATTERNS.forEach((pattern) => {
    if (pattern.test(source)) {
      fail(`static ebook prose repeats source-authority phrasing: ${pattern}`);
      return;
    }
    patternsValidated += 1;
  });

  return patternsValidated;
}

function findStaticEbookExtraLocaleFoodBeverageSourceOffenders(source) {
  const offenders = [];
  let chapterId = null;
  let lang = null;

  source.split('\n').forEach((line, index) => {
    const chapterMatch = line.match(/^    (\d+): \{$/);
    if (chapterMatch) {
      chapterId = chapterMatch[1];
      lang = null;
      return;
    }

    const langMatch = line.match(
      /^        (?:(?:'([^']+)')|([a-z][a-z0-9-]*)):\s*(?:`|'|"|svStudyBrief\()/,
    );
    if (langMatch) {
      lang = langMatch[1] || langMatch[2];
    }

    if (
      !STATIC_EBOOK_FOOD_BEVERAGE_SOURCE_CHAPTER_IDS.includes(chapterId) ||
      lang === 'en' ||
      lang === 'sv'
    ) {
      return;
    }

    STATIC_EBOOK_EXTRA_LOCALE_FOOD_BEVERAGE_SOURCE_TOKEN_PATTERNS.forEach((pattern) => {
      if (pattern.test(line)) {
        offenders.push({
          chapterId,
          line: index + 1,
          lang: lang || 'unknown',
          token: String(pattern),
          text: line.trim(),
        });
      }
    });
  });

  return offenders;
}

function validateStaticEbookExtraLocaleFoodBeverageSource() {
  const offenders = findStaticEbookExtraLocaleFoodBeverageSourceOffenders(
    loadText('site/ebook.js'),
  );
  if (offenders.length > 0) {
    offenders.forEach((offender) => {
      fail(
        `static ebook chapter ${offender.chapterId} ${offender.lang} source contains English food/beverage token ${offender.token} on line ${offender.line}: ${offender.text}`,
      );
    });
  }
  return {
    chaptersValidated: STATIC_EBOOK_FOOD_BEVERAGE_SOURCE_CHAPTER_IDS.length,
    patternsValidated: STATIC_EBOOK_EXTRA_LOCALE_FOOD_BEVERAGE_SOURCE_TOKEN_PATTERNS.length,
    offenders,
    parityValidated: offenders.length === 0,
  };
}

function validateStaticEbookSomaliHolidayFoodNaturalness() {
  const harness = createStaticEbookValidationHarness(readStaticEbookChapterIds());
  const html = renderStaticEbookChapter(harness, 'so', '13');
  let patternsValidated = 0;
  let requiredCopyValidated = 0;
  let valid = true;

  STATIC_EBOOK_SOMALI_HOLIDAY_FOOD_TOKEN_PATTERNS.forEach((pattern) => {
    if (pattern.test(html)) {
      valid = false;
      fail(`static ebook Somali chapter 13 contains English food token: ${pattern}`);
      return;
    }
    patternsValidated += 1;
  });

  STATIC_EBOOK_SOMALI_HOLIDAY_FOOD_REQUIRED_COPY.forEach((copy) => {
    if (!html.includes(copy)) {
      valid = false;
      fail(`static ebook Somali chapter 13 missing localized holiday-food copy: ${copy}`);
      return;
    }
    requiredCopyValidated += 1;
  });

  return {
    patternsValidated,
    requiredCopyValidated,
    parityValidated:
      valid &&
      patternsValidated === STATIC_EBOOK_SOMALI_HOLIDAY_FOOD_TOKEN_PATTERNS.length &&
      requiredCopyValidated === STATIC_EBOOK_SOMALI_HOLIDAY_FOOD_REQUIRED_COPY.length,
  };
}

function readStaticEbookChapterIds() {
  const context = { console, window: {} };
  context.globalThis = context;
  vm.runInNewContext(loadText('site/questions.js'), context, {
    filename: 'site/questions.js',
  });

  const meta = context.window.SMT_CHAPTERS_META || context.SMT_CHAPTERS_META;
  if (!Array.isArray(meta)) {
    fail('site/questions.js should expose SMT_CHAPTERS_META for static ebook validation');
    return ['intro'];
  }

  return ['intro', ...meta.map((chapter) => String(chapter.id))];
}

function createStaticEbookValidationHarness(chapterIds) {
  const reader = { innerHTML: '', scrollTop: 0 };
  const navAnchors = chapterIds.map((id) => ({
    dataset: { eb: id },
    classList: { toggle() {} },
  }));
  const localStorageValues = new Map();
  const localStorage = {
    getItem(key) {
      return localStorageValues.has(key) ? localStorageValues.get(key) : null;
    },
    setItem(key, value) {
      localStorageValues.set(key, String(value));
    },
  };
  const location = { hash: '#/ebook' };
  const scrollEvents = [];
  const document = {
    addEventListener() {},
    getElementById(id) {
      if (id === 'ebook-reader') return reader;
      if (reader.innerHTML.includes(`id="${id}"`)) {
        return {
          scrollIntoView(options) {
            scrollEvents.push({ id, options });
          },
        };
      }
      return null;
    },
    querySelectorAll(selector) {
      return selector === '.ebook__nav a[data-eb]' ? navAnchors : [];
    },
  };
  const window = {
    addEventListener() {},
    localStorage,
    location,
    smtApplyEbookHighlights() {},
  };
  const context = {
    console,
    document,
    localStorage,
    location,
    setTimeout(callback) {
      callback();
      return 0;
    },
    window,
  };
  context.globalThis = context;

  vm.runInNewContext(loadText('site/ebook.js'), context, { filename: 'site/ebook.js' });

  return { localStorage, location, reader, scrollEvents, window };
}

function staticEbookRouteHash(chapterId, targetParam, targetId) {
  return `#/ebook?c=${encodeURIComponent(chapterId)}&${targetParam}=${encodeURIComponent(
    targetId,
  )}`;
}

function renderStaticEbookHash(harness, lang, hash) {
  harness.localStorage.setItem('smt_lang', lang);
  harness.location.hash = hash;
  harness.reader.innerHTML = '';
  const scrollStart = harness.scrollEvents.length;
  harness.window.smtEbookRender();
  return {
    html: harness.reader.innerHTML,
    scrollEvents: harness.scrollEvents.slice(scrollStart),
  };
}

function renderStaticEbookChapter(harness, lang, chapterId) {
  return renderStaticEbookHash(harness, lang, `#/ebook?c=${encodeURIComponent(chapterId)}`).html;
}

function extractStaticEbookH1Parts(html) {
  const match = html.match(/<h1 class="ebook__h1"><span>([^<]+)<\/span>\s*<em>([^<]+)<\/em><\/h1>/);
  if (!match) return null;
  return { em: match[2], span: match[1] };
}

function validateStaticEbookChapter12HeadingParity() {
  const harness = createStaticEbookValidationHarness(readStaticEbookChapterIds());
  let localesValidated = 0;

  Object.entries(STATIC_EBOOK_CH12_HEADING_EXPECTATIONS).forEach(([language, expected]) => {
    const html = renderStaticEbookChapter(harness, language, '12');
    const actual = extractStaticEbookH1Parts(html);

    if (!actual) {
      fail(`static ebook chapter 12 ${language} render is missing the split H1 heading`);
      return;
    }

    if (actual.span !== expected.span || actual.em !== expected.em) {
      fail(
        `static ebook chapter 12 ${language} H1 drifted: expected "${expected.span} ${expected.em}", got "${actual.span} ${actual.em}"`,
      );
      return;
    }

    localesValidated += 1;
  });

  return {
    localesValidated,
    parityValidated:
      localesValidated === Object.keys(STATIC_EBOOK_CH12_HEADING_EXPECTATIONS).length,
  };
}

function validateStaticEbookExtraLocaleHolidayGlosses() {
  const harness = createStaticEbookValidationHarness(readStaticEbookChapterIds());
  const offenders = [];
  let languagesValidated = 0;

  STATIC_EBOOK_EXTRA_LOCALES.forEach((language) => {
    const html = renderStaticEbookChapter(harness, language, '13');
    const match = html.match(STATIC_EBOOK_CHAPTER13_ENGLISH_HOLIDAY_GLOSS_PATTERN);

    if (match) {
      offenders.push(`${language}: ${match[0]}`);
      return;
    }

    languagesValidated += 1;
  });

  if (offenders.length > 0) {
    fail(
      `static ebook chapter 13 extra-language copy contains parenthetical English holiday glosses:\n${offenders.join(
        '\n',
      )}`,
    );
  }

  return {
    languagesExpected: STATIC_EBOOK_EXTRA_LOCALES.length,
    languagesValidated,
    parityValidated:
      offenders.length === 0 && languagesValidated === STATIC_EBOOK_EXTRA_LOCALES.length,
  };
}

function staticEbookAnnotatedSourceClaimBlocks(html) {
  return Array.from(
    html.matchAll(
      /<(?:p|li)\b(?=[^>]*\bdata-source-claims="ebook")(?=[^>]*\bdata-source-scope="ebook")(?=[^>]*\bdata-source-keys="[^"]+")[^>]*>[\s\S]*?<\/(?:p|li)>/g,
    ),
    (match) => match[0],
  );
}

function staticEbookDataSourceKeys(block) {
  const match = block.match(/\bdata-source-keys="([^"]+)"/);
  return match ? match[1].split(/\s+/).filter(Boolean) : [];
}

function staticEbookSourceCountsFromBlocks(blocks) {
  const counts = {};
  blocks.forEach((block) => {
    Array.from(new Set(staticEbookDataSourceKeys(block))).forEach((key) => {
      counts[key] = (counts[key] || 0) + 1;
    });
  });
  return counts;
}

function staticEbookRenderedSourceCounts(html) {
  const match = html.match(/\bdata-source-counts='([^']+)'/);
  if (!match) return null;
  try {
    return JSON.parse(match[1]);
  } catch {
    return null;
  }
}

function normalizeStaticEbookSourceCounts(counts) {
  return Object.fromEntries(
    Object.keys(counts || {})
      .sort()
      .map((key) => [key, counts[key]]),
  );
}

function staticEbookSourceReferenceLinks(html) {
  return Array.from(
    html.matchAll(
      /<sup\b[^>]*\bid="(eb-[^"]+-fn-\d+)-ref"[^>]*>\s*<a\b[^>]*\bhref="([^"]+)"[^>]*>\[(\d+)\]<\/a>\s*<\/sup>/g,
    ),
    (match) => ({ id: match[1], href: match[2], index: Number(match[3]) }),
  );
}

function staticEbookRenderedFootnoteItems(html) {
  return Array.from(
    html.matchAll(
      /<li\b[^>]*\bid="(eb-[^"]+-fn-\d+)"[^>]*>\s*<a\b[^>]*\bhref="([^"]+)"[^>]*>\s*<span>(\d+)<\/span>\s*<\/a>/g,
    ),
    (match) => ({ id: match[1], href: match[2], index: Number(match[3]) }),
  );
}

function staticEbookHasNonUhrSource(counts) {
  return Object.keys(counts || {}).some((key) => !key.startsWith('uhr'));
}

function validateStaticEbookFootnoteHashParity() {
  const chapterIds = readStaticEbookChapterIds();
  const languages = ['en', 'sv'];
  const languageValid = new Map(languages.map((language) => [language, true]));
  const harness = createStaticEbookValidationHarness(chapterIds);
  let chaptersValidated = 0;
  let heterogeneousChaptersValidated = 0;
  let valid = true;

  function reject(language, chapterId, message) {
    valid = false;
    languageValid.set(language, false);
    fail(`static ebook ${language} chapter ${chapterId}: ${message}`);
  }

  chapterIds.forEach((chapterId) => {
    let chapterValid = true;

    languages.forEach((language) => {
      const html = renderStaticEbookChapter(harness, language, chapterId);
      const blocks = staticEbookAnnotatedSourceClaimBlocks(html);
      const referenceLinks = staticEbookSourceReferenceLinks(html);
      const footnoteItems = staticEbookRenderedFootnoteItems(html);
      const renderedCounts = staticEbookRenderedSourceCounts(html);
      const expectedCounts = staticEbookSourceCountsFromBlocks(blocks);
      const expectedCountJson = JSON.stringify(normalizeStaticEbookSourceCounts(expectedCounts));
      const renderedCountJson = JSON.stringify(normalizeStaticEbookSourceCounts(renderedCounts));

      function rejectCase(message) {
        chapterValid = false;
        reject(language, chapterId, message);
      }

      if (blocks.length === 0) {
        rejectCase('rendered no source-annotated prose blocks');
      }
      if (referenceLinks.length !== blocks.length) {
        rejectCase(
          `rendered ${referenceLinks.length} source reference links for ${blocks.length} annotated blocks`,
        );
      }
      if (footnoteItems.length !== blocks.length) {
        rejectCase(
          `rendered ${footnoteItems.length} footnotes for ${blocks.length} annotated blocks`,
        );
      }
      if (!renderedCounts) {
        rejectCase('missing parseable data-source-counts on provenance badge');
      } else if (renderedCountJson !== expectedCountJson) {
        rejectCase(
          `data-source-counts ${renderedCountJson} does not match annotated prose ${expectedCountJson}`,
        );
      }
      if (!staticEbookHasNonUhrSource(renderedCounts)) {
        rejectCase('source mix must include at least one non-UHR citation or editorial note');
      }

      referenceLinks.forEach((reference, index) => {
        const footnote = footnoteItems[index];
        if (!footnote) return;
        const expectedId = `eb-${chapterId}-${language}-fn-${index + 1}`;
        if (reference.id !== expectedId || footnote.id !== expectedId) {
          rejectCase(
            `footnote id drifted at index ${index + 1}; expected ${expectedId}, saw ${reference.id}/${footnote.id}`,
          );
        }
        if (reference.index !== index + 1 || footnote.index !== index + 1) {
          rejectCase(`footnote index drifted at ${expectedId}`);
        }
        const expectedReferenceHref = staticEbookRouteHash(chapterId, 'fn', expectedId);
        const expectedBackHref = staticEbookRouteHash(chapterId, 'fnref', expectedId);
        if (reference.href !== expectedReferenceHref) {
          rejectCase(`source reference href ${reference.href} should be ${expectedReferenceHref}`);
        }
        if (footnote.href !== expectedBackHref) {
          rejectCase(`footnote backlink href ${footnote.href} should be ${expectedBackHref}`);
        }
      });

      const firstFootnote = footnoteItems[0];
      if (firstFootnote) {
        const footnoteTarget = renderStaticEbookHash(
          harness,
          language,
          staticEbookRouteHash(chapterId, 'fn', firstFootnote.id),
        );
        if (!footnoteTarget.scrollEvents.some((event) => event.id === firstFootnote.id)) {
          rejectCase(`fn route did not scroll to ${firstFootnote.id}`);
        }

        const referenceTarget = renderStaticEbookHash(
          harness,
          language,
          staticEbookRouteHash(chapterId, 'fnref', firstFootnote.id),
        );
        if (!referenceTarget.scrollEvents.some((event) => event.id === `${firstFootnote.id}-ref`)) {
          rejectCase(`fnref route did not scroll to ${firstFootnote.id}-ref`);
        }
      }
    });

    if (chapterValid) {
      chaptersValidated += 1;
      heterogeneousChaptersValidated += 1;
    }
  });

  return {
    chaptersValidated,
    heterogeneousChaptersValidated,
    languagesValidated: Array.from(languageValid.values()).filter(Boolean).length,
    parityValidated:
      valid &&
      chaptersValidated === chapterIds.length &&
      heterogeneousChaptersValidated === chapterIds.length &&
      Array.from(languageValid.values()).every(Boolean),
  };
}

function validateStaticEbookProseSourceMetadata() {
  const source = loadText('site/ebook.js');
  let rulesValidated = 0;

  const forbiddenPatterns = [
    {
      pattern: /EBOOK_DEFAULT_PROSE_SOURCE_KEYS/,
      message: 'static ebook prose source metadata must not define a default source-key fallback',
    },
    {
      pattern: /fallbackSourceKeys\s*=\s*EBOOK_DEFAULT_PROSE_SOURCE_KEYS/,
      message: 'static ebook annotate() must not default to broad UHR prose source keys',
    },
    {
      pattern: /explicitSourceKeys\s*\|\|\s*fallbackSourceKeys/,
      message: 'static ebook annotate() must not annotate prose through fallbackSourceKeys',
    },
    {
      pattern: /typeof point === 'string' \? null : point\.sourceKeys/,
      message: 'static ebook Swedish brief string points must carry local source keys',
    },
    {
      pattern: /footnoteCollector\.annotate\(rawBodyHtml\)/,
      message: 'static ebook body annotation must pass typed chapter source metadata',
    },
    {
      pattern: /<a href="\$\{note\.url\}">\$\{note\.label\}<\/a>/,
      message: 'static ebook sourceLink(note) must not render unguarded external anchors',
    },
    {
      pattern: /<a href="\$\{source\.url\}">\$\{source\.label\}<\/a>/,
      message: 'static ebook official source links must not render unguarded external anchors',
    },
  ];
  const requiredSnippets = [
    {
      snippet: 'const EBOOK_BODY_SOURCE_KEYS = Object.freeze({',
      message: 'static ebook must define typed body source metadata per chapter',
    },
    {
      snippet: 'function ebookBodySourceKeys(chapterId) {',
      message: 'static ebook must resolve typed body source metadata before annotation',
    },
    {
      snippet: 'annotate(html, typedSourceKeys) {',
      message:
        'static ebook annotate() must require typed source metadata when inline keys are absent',
    },
    {
      snippet: 'const normalizedTypedSourceKeys = typedSourceKeys',
      message: 'static ebook annotate() must normalize typed source metadata before footnotes',
    },
    {
      snippet: 'data-source-metadata="${metadataKind}"',
      message:
        'static ebook rendered prose must expose whether source metadata was inline or typed',
    },
    {
      snippet: 'footnoteCollector.annotate(rawBodyHtml, ebookBodySourceKeys(id))',
      message: 'static ebook body render must pass typed chapter source metadata',
    },
    {
      snippet:
        "const normalizedBriefSourceKeys = normalizedEbookSourceKeys(\n      sourceKeys,\n      'svStudyBrief body source metadata',",
      message: 'static ebook Swedish study brief must normalize local source keys',
    },
    {
      snippet: '? normalizedBriefSourceKeys : point.sourceKeys;',
      message: 'static ebook Swedish study brief string points must use local source metadata',
    },
    {
      snippet: '<p${ebookSourceKeyDataAttr(EBOOK_EDITORIAL_ONLY_SOURCE_KEYS)}>',
      message: 'static ebook Swedish practice hints must be marked as editorial prose',
    },
    {
      snippet: 'function sourceAnchor(note) {',
      message: 'static ebook must centralize source anchors for safe external-link attributes',
    },
    {
      snippet: '? \' target="_blank" rel="noreferrer"\'',
      message: 'static ebook external source anchors must use target blank and noreferrer',
    },
    {
      snippet: 'OFFICIAL_TEST_SOURCE_NOTES.map((source) => sourceAnchor(source, lang)).join',
      message: 'static ebook official source note links must use the safe source anchor helper',
    },
  ];

  forbiddenPatterns.forEach(({ pattern, message }) => {
    if (pattern.test(source)) {
      fail(message);
      return;
    }
    rulesValidated += 1;
  });

  requiredSnippets.forEach(({ snippet, message }) => {
    if (!source.includes(snippet)) {
      fail(message);
      return;
    }
    rulesValidated += 1;
  });

  return {
    rulesValidated,
    rulesExpected: forbiddenPatterns.length + requiredSnippets.length,
  };
}

const STATIC_EBOOK_CIVIC_TERM_GLOSS_LANGUAGES = [
  'zh-Hans',
  'zh-Hant',
  'ar',
  'ckb',
  'fa',
  'pl',
  'so',
  'ti',
  'tr',
  'uk',
];
const STATIC_EBOOK_BARE_CIVIC_TERM_PATTERN =
  /(^|[^\p{L}\p{N}_-])(region|kommun)(?=$|[^\p{L}\p{N}_-])/giu;

function validateStaticEbookCivicTermGlosses() {
  const chapterIds = readStaticEbookChapterIds();
  const harness = createStaticEbookValidationHarness(chapterIds);
  let checksValidated = 0;
  let valid = true;

  chapterIds.forEach((chapterId) => {
    STATIC_EBOOK_CIVIC_TERM_GLOSS_LANGUAGES.forEach((language) => {
      const html = renderStaticEbookChapter(harness, language, chapterId);
      const offenders = Array.from(
        html.matchAll(STATIC_EBOOK_BARE_CIVIC_TERM_PATTERN),
        (match) => ({
          context: staticEbookCivicTermContext(html, match.index ?? 0),
          term: match[2],
        }),
      );

      if (offenders.length > 0) {
        valid = false;
        fail(
          `static ebook ${language} chapter ${chapterId} contains bare civic terms: ${offenders
            .map((offender) => `${offender.term} in "${offender.context}"`)
            .join('; ')}`,
        );
        return;
      }

      checksValidated += 1;
    });
  });

  return {
    checksExpected: chapterIds.length * STATIC_EBOOK_CIVIC_TERM_GLOSS_LANGUAGES.length,
    checksValidated,
    parityValidated: valid,
  };
}

function staticEbookCivicTermContext(html, index) {
  return html
    .slice(Math.max(0, index - 90), index + 150)
    .replace(/<[^>]*>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function validateStaticV11ReadinessCopy() {
  const source = loadText('site/v11.js');
  const offenders = findUnsupportedStaticV11ReadinessCopyInSource(source);
  const missing = findMissingStaticV11ReadinessCopyInSource(source);

  if (offenders.length > 0) {
    fail(
      `static v1.1 dashboard exposes unsupported readiness/pass-prediction copy:\n${formatStaticV11ReadinessCopyIssues(
        offenders,
      )}`,
    );
  }

  if (missing.length > 0) {
    fail(
      `static v1.1 dashboard is missing local-practice labels, component labels, or non-official caveats:\n${formatStaticV11ReadinessCopyIssues(
        missing,
      )}`,
    );
  }

  return {
    requiredCopyValidated: STATIC_V11_REQUIRED_READINESS_COPY.length - missing.length,
    unsupportedPatternsValidated:
      STATIC_V11_UNSUPPORTED_READINESS_COPY_PATTERNS.length - offenders.length,
  };
}

const STATIC_SITE_SWEDISH_STUDY_TERM_FORBIDDEN = [
  /Spaced repetition/i,
  /\bquiz\b/i,
  /\btiming\b/i,
  /litet quiz/i,
  /riktig timing/i,
];

const STATIC_SITE_SWEDISH_STUDY_TERM_REQUIRED = [
  'Repetition med intervall',
  'kort övning',
  'tidsatt övning',
];
const STATIC_SITE_SWEDISH_GRAMMAR_TONE_FORBIDDEN = [
  /ingen juridiska/i,
  /fika-stor/i,
  /fika-skador/i,
];
const STATIC_SITE_SWEDISH_GRAMMAR_TONE_REQUIRED = [
  /inget juridiskt kr[aå]ngel/i,
  /en kort studievana/i,
  /inte ansvariga f[oö]r missade deadlines, avslagna ans[oö]kningar eller beslut/i,
];
const STATIC_EBOOK_SWEDISH_STUDY_TERM_FORBIDDEN = [
  /gör ett\s+quiz/i,
  new RegExp(['quiz', 'frågor'].join(''), 'i'),
  new RegExp(['quiz', 'pass'].join(''), 'i'),
  /quizet/i,
  /provexempel/i,
];
const STATIC_EBOOK_SWEDISH_STUDY_TERM_REQUIRED = [
  'gör en övning',
  'Starta övningsprov',
  'gör ett övningsprov',
];
const STATIC_I18N_CHINESE_LOCALES = ['zh-Hans', 'zh-Hant'];
const STATIC_I18N_CHINESE_TEXT_PATTERN = /[\u3400-\u9fff]/;
const STATIC_I18N_ASCII_SENTENCE_PUNCTUATION_NEAR_CHINESE =
  /[\u3400-\u9fff][,:;?!.]|[,:;?!.][\u3400-\u9fff]/;

function validateStaticSiteSwedishStudyTerms() {
  const source = loadText('site/app.js');
  const swedishDictionary = source.match(/\n  sv: \{([\s\S]*?)\n  \}\n\};/)?.[1];
  let forbiddenTermsValidated = 0;
  let requiredTermsValidated = 0;

  if (!swedishDictionary) {
    fail('static site Swedish dictionary block must stay parseable');
    return {
      forbiddenTermsValidated,
      requiredTermsValidated,
    };
  }

  STATIC_SITE_SWEDISH_STUDY_TERM_FORBIDDEN.forEach((pattern) => {
    if (pattern.test(swedishDictionary)) {
      fail(`static site Swedish dictionary contains English study term: ${pattern}`);
      return;
    }
    forbiddenTermsValidated += 1;
  });

  STATIC_SITE_SWEDISH_STUDY_TERM_REQUIRED.forEach((term) => {
    if (!swedishDictionary.includes(term)) {
      fail(`static site Swedish dictionary missing natural study term: ${term}`);
      return;
    }
    requiredTermsValidated += 1;
  });

  return {
    forbiddenTermsValidated,
    requiredTermsValidated,
  };
}

