function stripAllowedStaticI18nTokens(value) {
  return value
    .replace(/<[^>]*>/g, ' ')
    .replace(/https?:\/\/\S+/gi, ' ')
    .replace(/#[/a-z0-9_-]+/gi, ' ')
    .replace(
      /\b(?:Almost Swedish|Google AdSense|Google Mobile Ads|AdMob|Cookie|cookies|UHR|Skolverket|Migrationsverket|BankID|MVP|EN|SV|SEK|Jantelagen|Allemansrätten|Lagom|Fika|fika)\b/g,
      ' ',
    );
}

function validateStaticI18nChinesePunctuation() {
  let localesValidated = 0;
  let valuesValidated = 0;
  let valid = true;
  let dictionaries;

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    dictionaries = loadStaticI18nExtras();
  } catch (error) {
    reject(`site/i18n-extras.js must stay parseable for static i18n validation: ${error.message}`);
    return { localesValidated, valuesValidated, valid };
  }

  for (const locale of STATIC_I18N_CHINESE_LOCALES) {
    const dictionary = dictionaries?.[locale];
    if (!dictionary || typeof dictionary !== 'object' || Array.isArray(dictionary)) {
      reject(`static i18n extra dictionary ${locale} must exist`);
      continue;
    }
    localesValidated += 1;

    for (const [key, value] of Object.entries(dictionary)) {
      if (typeof value !== 'string') {
        reject(`static i18n extra ${locale}.${key} must be a string`);
        continue;
      }
      if (!STATIC_I18N_CHINESE_TEXT_PATTERN.test(value)) continue;

      const learnerText = stripAllowedStaticI18nTokens(value);
      if (STATIC_I18N_ASCII_SENTENCE_PUNCTUATION_NEAR_CHINESE.test(learnerText)) {
        reject(
          `static i18n extra ${locale}.${key} uses Latin sentence punctuation near Chinese text`,
        );
        continue;
      }
      valuesValidated += 1;
    }
  }

  if (valuesValidated === 0) {
    reject('static i18n Chinese punctuation guard must inspect learner-facing values');
  }

  return { localesValidated, valuesValidated, valid };
}

function questionSentenceEndingsAreComplete(question) {
  return ['questionSv', 'questionEn', 'explanationSv', 'explanationEn'].every((field) =>
    textHasSentenceEnding(question[field]),
  );
}

function validateCitizenshipRequirementsSourceAuthorityCopy() {
  let valid = true;
  let fieldsValidated = 0;

  function reject(message) {
    valid = false;
    fail(message);
  }

  if (!Array.isArray(citizenshipRequirementAreas)) {
    reject('citizenship requirement areas must be loadable from data/citizenshipRequirements.ts');
    return;
  }

  for (const area of citizenshipRequirementAreas) {
    for (const field of ['summary', 'detail']) {
      const localizedText = area[field];

      for (const language of ['sv', 'en']) {
        const text = localizedText?.[language];

        if (typeof text !== 'string' || !text.trim()) {
          reject(`citizenship requirement ${area.id}.${field}.${language} must be non-empty`);
          continue;
        }

        const sourceAuthorityPattern = CITIZENSHIP_REQUIREMENTS_SOURCE_AUTHORITY_PATTERNS.find(
          (pattern) => pattern.test(text),
        );

        if (sourceAuthorityPattern) {
          reject(
            `citizenship requirement ${area.id}.${field}.${language} must state facts neutrally; source rows carry provenance`,
          );
          continue;
        }

        fieldsValidated += 1;
      }
    }
  }

  citizenshipRequirementsCopyFieldsValidated = fieldsValidated;
  citizenshipRequirementsSourceAuthorityCopyParityValidated =
    valid && fieldsValidated === citizenshipRequirementAreas.length * 4;
}

const EXPECTED_CITIZENSHIP_TIMELINE_RETURN_KEYS = [
  'countdownCopyParity',
  'homeMountParity',
  'homeMountRulesValidated',
  'dateParity',
  'firstSittingDate',
  'rulesDate',
  'sourceUrlsValidated',
  'testDeadlineDate',
];

function validateCitizenshipTimelineReturnShape() {
  let valid = true;
  const validatorSource = fs.readFileSync(__filename, 'utf8');
  const returnMatch = validatorSource.match(
    /function validateCitizenshipTimeline\(\) \{[\s\S]*?\n\s+return\s+\{([\s\S]*?)\n\s+\};\n\}/,
  );

  if (!returnMatch) {
    fail('validateCitizenshipTimeline return shape must stay source-checkable');
    citizenshipTimelineReturnShapeKeysValidated = false;
    return false;
  }

  const returnKeys = [...returnMatch[1].matchAll(/^\s*([A-Za-z_$][\w$]*)\s*(?=,|:)/gm)].map(
    (match) => match[1],
  );
  const duplicateKeys = returnKeys.filter((key, index) => returnKeys.indexOf(key) !== index);
  const missingKeys = EXPECTED_CITIZENSHIP_TIMELINE_RETURN_KEYS.filter(
    (key) => !returnKeys.includes(key),
  );
  const extraKeys = returnKeys.filter(
    (key) => !EXPECTED_CITIZENSHIP_TIMELINE_RETURN_KEYS.includes(key),
  );

  if (duplicateKeys.length > 0) {
    valid = false;
    fail(
      `validateCitizenshipTimeline return shape must not duplicate keys: ${[
        ...new Set(duplicateKeys),
      ].join(', ')}`,
    );
  }
  if (missingKeys.length > 0) {
    valid = false;
    fail(`validateCitizenshipTimeline return shape missing keys: ${missingKeys.join(', ')}`);
  }
  if (extraKeys.length > 0) {
    valid = false;
    fail(`validateCitizenshipTimeline return shape has unexpected keys: ${extraKeys.join(', ')}`);
  }

  citizenshipTimelineReturnShapeKeysValidated =
    valid && returnKeys.length === EXPECTED_CITIZENSHIP_TIMELINE_RETURN_KEYS.length;
  return citizenshipTimelineReturnShapeKeysValidated;
}

function validateCitizenshipTimeline() {
  let dateParity = true;
  let countdownCopyParity = true;
  let homeMountParity = true;
  let homeMountRulesValidated = 0;
  const sourceUrls = examDateModule.CITIZENSHIP_TIMELINE_SOURCE_URLS;
  const rulesDate = dateIsoDay(examDateModule.CITIZENSHIP_RULES_EFFECTIVE_DATE);
  const firstSittingDate = dateIsoDay(examDateModule.CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE);
  const testDeadlineDate = dateIsoDay(examDateModule.CIVIC_KNOWLEDGE_TEST_DEADLINE_DATE);

  function rejectDate(message) {
    dateParity = false;
    fail(message);
  }

  function rejectCountdown(message) {
    countdownCopyParity = false;
    fail(message);
  }

  function rejectHomeMount(message) {
    homeMountParity = false;
    fail(message);
  }

  if (rulesDate !== EXPECTED_CITIZENSHIP_RULES_EFFECTIVE_DATE) {
    rejectDate(
      `citizenship rules effective date must be ${EXPECTED_CITIZENSHIP_RULES_EFFECTIVE_DATE}`,
    );
  }
  if (firstSittingDate !== EXPECTED_CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE) {
    rejectDate(
      `civic knowledge test first sitting must be ${EXPECTED_CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE}`,
    );
  }
  if (testDeadlineDate !== EXPECTED_CIVIC_KNOWLEDGE_TEST_DEADLINE_DATE) {
    rejectDate(
      `civic knowledge test deadline must be ${EXPECTED_CIVIC_KNOWLEDGE_TEST_DEADLINE_DATE}`,
    );
  }
  if (
    !(examDateModule.CITIZENSHIP_RULES_EFFECTIVE_DATE instanceof Date) ||
    !(examDateModule.CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE instanceof Date) ||
    !(examDateModule.CIVIC_KNOWLEDGE_TEST_DEADLINE_DATE instanceof Date) ||
    examDateModule.CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE.getTime() <=
      examDateModule.CITIZENSHIP_RULES_EFFECTIVE_DATE.getTime() ||
    examDateModule.CIVIC_KNOWLEDGE_TEST_DEADLINE_DATE.getTime() <=
      examDateModule.CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE.getTime()
  ) {
    rejectDate(
      'civic knowledge test first sitting and deadline must stay after the citizenship rules date',
    );
  }
  if (dateIsoDay(examDateModule.EXAM_REFORM_DATE) !== rulesDate) {
    rejectDate('EXAM_REFORM_DATE must remain an alias for the citizenship rules date');
  }

  let sourceUrlsValidated = 0;
  Object.entries(EXPECTED_CITIZENSHIP_TIMELINE_SOURCE_URLS).forEach(([key, expectedUrl]) => {
    const actualUrl = sourceUrls?.[key];
    if (actualUrl !== expectedUrl) {
      rejectDate(`citizenship timeline source URL ${key} must be ${expectedUrl}`);
      return;
    }
    if (!actualUrl.startsWith('https://')) {
      rejectDate(`citizenship timeline source URL ${key} must use HTTPS`);
      return;
    }
    sourceUrlsValidated += 1;
  });

  const countdownBannerSource = fs.readFileSync(
    path.join(repoRoot, 'components/ui/CountdownBanner.tsx'),
    'utf8',
  );

  [
    'CITIZENSHIP_RULES_EFFECTIVE_DATE',
    'CIVIC_KNOWLEDGE_TEST_FIRST_SITTING_DATE',
    'Nya medborgarskapsregler gäller från',
    'Första provomgången i samhällskunskap hålls',
    'New citizenship rules apply from',
    'The first civic-knowledge test sitting is on',
  ].forEach((requiredText) => {
    if (!countdownBannerSource.includes(requiredText)) {
      rejectCountdown(`CountdownBanner missing timeline copy or constant: ${requiredText}`);
    }
  });

  [
    /Det nya samhällskunskapstestet träder i kraft/,
    /The new civic knowledge test takes effect/,
    /until new exam/,
    /tills nya provet/,
    /UHR har\s+bekräftat/,
    /UHR has\s+confirmed/,
  ].forEach((forbiddenPattern) => {
    if (forbiddenPattern.test(countdownBannerSource)) {
      rejectCountdown(
        'CountdownBanner must state timeline facts neutrally and keep source authority in source links',
      );
    }
  });

  const homeRouteSource = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/home.tsx'), 'utf8');
  [
    {
      message: 'Home route must import CountdownBanner',
      pattern:
        /import\s+\{\s*CountdownBanner\s*\}\s+from\s+['"][^'"]*components\/ui\/CountdownBanner['"]/,
    },
    {
      message: 'Home route must mount CountdownBanner with the selected language',
      pattern: /<CountdownBanner\s+language=\{language\}\s*\/>/,
    },
  ].forEach(({ message, pattern }) => {
    if (!pattern.test(homeRouteSource)) {
      rejectHomeMount(message);
      return;
    }
    homeMountRulesValidated += 1;
  });

  return {
    countdownCopyParity,
    homeMountParity,
    homeMountRulesValidated,
    dateParity,
    firstSittingDate,
    rulesDate,
    sourceUrlsValidated,
    testDeadlineDate,
  };
}

function validateCountdownBannerHomeMount() {
  let valid = true;
  const homeRouteSource = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/home.tsx'), 'utf8');
  const rules = [
    {
      label: 'Home route must import CountdownBanner',
      pattern: /import \{ CountdownBanner \} from '..\/..\/components\/ui\/CountdownBanner';/,
    },
    {
      label: 'Home route must mount CountdownBanner with the selected language',
      pattern: /<CountdownBanner language=\{language\} \/>/,
    },
  ];

  rules.forEach(({ label, pattern }) => {
    if (!pattern.test(homeRouteSource)) {
      valid = false;
      fail(label);
      return;
    }
    countdownBannerHomeMountRulesValidated += 1;
  });

  countdownBannerHomeMountParityValidated = valid && countdownBannerHomeMountRulesValidated === 2;
}

function validateStudyPlanRuntime() {
  const { daysUntil, formatExamDate, generateStudyPlan } = examDateModule;
  let valid = true;

  if (
    typeof daysUntil !== 'function' ||
    typeof formatExamDate !== 'function' ||
    typeof generateStudyPlan !== 'function'
  ) {
    fail('study plan runtime helpers must be exported');
    return;
  }

  const validNow = new Date('2026-05-19T00:00:00.000Z');
  const invalidDate = new Date('not-a-date');
  const baseStudyPlanInput = {
    testDate: new Date('2026-06-15T00:00:00.000Z'),
    now: validNow,
    intensity: 'regular',
  };
  const cases = [
    {
      label: 'invalid dates use safe fallbacks',
      actual: () =>
        daysUntil(invalidDate, validNow) === 0 &&
        daysUntil(new Date('2026-06-15T00:00:00.000Z'), invalidDate) === 0 &&
        formatExamDate(invalidDate, 'en') === 'date unavailable' &&
        formatExamDate(invalidDate, 'sv') === 'datum saknas',
    },
    {
      label: 'NaN dates and unknown intensity normalize',
      actual: () => {
        const plan = generateStudyPlan({
          testDate: invalidDate,
          now: invalidDate,
          totalQuestions: Number.NaN,
          masteredQuestions: Number.POSITIVE_INFINITY,
          mocksTaken: '2',
          intensity: 'turbo',
        });
        return (
          plan.hasTestDate === true &&
          plan.daysRemaining === 0 &&
          plan.intensity === 'regular' &&
          plan.mocksRemaining === 6 &&
          Number.isFinite(Date.parse(plan.testDateIso)) &&
          Number.isFinite(Date.parse(plan.generatedAt)) &&
          Number.isFinite(plan.dailyQuestionTarget) &&
          plan.dailyQuestionTarget >= 5 &&
          plan.dailyQuestionTarget <= 80 &&
          Number.isInteger(plan.weeklyMockTarget) &&
          plan.weeklyMockTarget >= 1 &&
          plan.weeklyMockTarget <= 2
        );
      },
    },
    {
      label: 'string counts do not coerce into progress',
      actual: () => {
        const plan = generateStudyPlan({
          ...baseStudyPlanInput,
          totalQuestions: '200',
          masteredQuestions: '10',
          mocksTaken: '2',
        });
        return (
          plan.mocksRemaining === 6 &&
          Number.isFinite(plan.dailyQuestionTarget) &&
          plan.dailyQuestionTarget >= 5 &&
          plan.dailyQuestionTarget <= 80
        );
      },
    },
    {
      label: 'fractional counts do not coerce into progress',
      actual: () => {
        const plan = generateStudyPlan({
          ...baseStudyPlanInput,
          totalQuestions: 200.5,
          masteredQuestions: 10.5,
          mocksTaken: 1.5,
        });
        return (
          plan.mocksRemaining === 6 &&
          Number.isFinite(plan.dailyQuestionTarget) &&
          plan.dailyQuestionTarget >= 5 &&
          plan.dailyQuestionTarget <= 80
        );
      },
    },
    {
      label: 'mastered questions and mocks are clamped',
      actual: () => {
        const plan = generateStudyPlan({
          ...baseStudyPlanInput,
          totalQuestions: 10,
          masteredQuestions: 99,
          mocksTaken: 99,
        });
        return (
          plan.mocksRemaining === 0 &&
          Number.isFinite(plan.dailyQuestionTarget) &&
          plan.dailyQuestionTarget >= 5 &&
          plan.dailyQuestionTarget <= 80
        );
      },
    },
    {
      label: 'valid regular plan remains bounded',
      actual: () => {
        const plan = generateStudyPlan({
          ...baseStudyPlanInput,
          totalQuestions: 200,
          masteredQuestions: 0,
          mocksTaken: 0,
        });
        return (
          plan.hasTestDate === true &&
          plan.daysRemaining === 27 &&
          plan.mocksRemaining === 6 &&
          plan.isCrunch === false &&
          plan.dailyQuestionTarget >= 5 &&
          plan.dailyQuestionTarget <= 80 &&
          plan.weeklyMockTarget >= 1 &&
          plan.weeklyMockTarget <= 2
        );
      },
    },
  ];

  cases.forEach(({ label, actual }) => {
    let passed = false;
    try {
      passed = actual() === true;
    } catch (error) {
      fail(`study plan runtime ${label} threw: ${error.message}`);
      valid = false;
      return;
    }

    if (!passed) {
      fail(`study plan runtime failed: ${label}`);
      valid = false;
      return;
    }
    studyPlanRuntimeCasesValidated += 1;
  });

  studyPlanRuntimeParityValidated = valid && studyPlanRuntimeCasesValidated === 6;
}

function validateCountdownBannerFocusedParity() {
  validateCitizenshipTimelineReturnShape();
  const timelineValidation = validateCitizenshipTimeline();
  citizenshipRulesEffectiveDateValidated = timelineValidation.rulesDate;
  civicKnowledgeTestFirstSittingDateValidated = timelineValidation.firstSittingDate;
  civicKnowledgeTestDeadlineDateValidated = timelineValidation.testDeadlineDate;
  citizenshipTimelineSourceUrlsValidated = timelineValidation.sourceUrlsValidated;
  citizenshipTimelineDateParityValidated = timelineValidation.dateParity;
  countdownBannerTimelineCopyParityValidated = timelineValidation.countdownCopyParity;
  validateCountdownBannerHomeMount();
  validateStudyPlanRuntime();
}

function findQuestionAuthorityOverclaim(question) {
  const text = [
    question.questionSv,
    question.questionEn,
    question.explanationSv,
    question.explanationEn,
    ...(question.options || []).flatMap((option) => [option.textSv, option.textEn]),
  ].join(' ');

  return QUESTION_AUTHORITY_OVERCLAIM_PATTERNS.find((pattern) => pattern.test(text));
}

function findQuestionStemSourceAuthorityReference(question) {
  const text = [question.questionSv, question.questionEn].join(' ');

  return findSourceAuthorityStemPattern(text);
}

function findQuestionNestedMetaStem(question) {
  const text = [question.questionSv, question.questionEn].join(' ');

  return QUESTION_NESTED_META_STEM_PATTERNS.find((pattern) => pattern.test(text));
}

function findQuestionJudgementMetaStem(question) {
  const text = [question.questionSv, question.questionEn].join(' ');

  return QUESTION_JUDGEMENT_META_STEM_PATTERNS.find((pattern) => pattern.test(text));
}

function findQuestionGeneratedTrueFalseNaturalnessIssue(question) {
  if (question.type !== 'true_false') return null;
  if (
    question.tags?.includes('published-variant') &&
    /\bi Sverige\b/i.test(question.questionSv) &&
    !/\bSweden\b|\bin Sweden\b/i.test(question.questionEn)
  ) {
    return 'generated true/false English stem drops Sweden scope';
  }

  return (
    findGeneratedTrueFalseNaturalnessPatternMatch(question.questionSv) ||
    findGeneratedTrueFalseNaturalnessPatternMatch(question.questionEn)
  );
}

