function isColorToken(value) {
  return (
    typeof value === 'string' && (/^#[0-9a-fA-F]{6}$/.test(value) || /^rgba?\(.+\)$/.test(value))
  );
}

function relativeLuminance(color) {
  const match = /^#([0-9a-fA-F]{6})$/.exec(color || '');
  if (!match) return null;
  const channels = [0, 2, 4].map((index) => parseInt(match[1].slice(index, index + 2), 16) / 255);
  const [red, green, blue] = channels.map((channel) =>
    channel <= 0.03928 ? channel / 12.92 : ((channel + 0.055) / 1.055) ** 2.4,
  );
  return 0.2126 * red + 0.7152 * green + 0.0722 * blue;
}

function contrastRatio(foreground, background) {
  const foregroundLuminance = relativeLuminance(foreground);
  const backgroundLuminance = relativeLuminance(background);
  if (foregroundLuminance === null || backgroundLuminance === null) return null;
  const lighter = Math.max(foregroundLuminance, backgroundLuminance);
  const darker = Math.min(foregroundLuminance, backgroundLuminance);
  return (lighter + 0.05) / (darker + 0.05);
}

function extractStringConstantFromTs(source, constantName) {
  const sourceFile = ts.createSourceFile('source.tsx', source, ts.ScriptTarget.Latest, true);
  let value;

  function visit(node) {
    if (
      ts.isVariableDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === constantName &&
      node.initializer &&
      ts.isStringLiteralLike(node.initializer)
    ) {
      value = node.initializer.text;
      return;
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return value;
}

function extractStringUnionTypeFromTs(source, typeName) {
  const sourceFile = ts.createSourceFile('source.ts', source, ts.ScriptTarget.Latest, true);
  let values;

  function visit(node) {
    if (
      ts.isTypeAliasDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === typeName &&
      ts.isUnionTypeNode(node.type)
    ) {
      values = node.type.types.map((typeNode) => {
        if (ts.isLiteralTypeNode(typeNode) && typeNode.literal) {
          if (ts.isStringLiteralLike(typeNode.literal)) {
            return typeNode.literal.text;
          }
          if (ts.isNumericLiteral(typeNode.literal)) {
            return Number(typeNode.literal.text);
          }
        }
        return undefined;
      });
      return;
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return values;
}

function extractTypeAliasTextFromTs(source, typeName) {
  const sourceFile = ts.createSourceFile('source.ts', source, ts.ScriptTarget.Latest, true);
  let text;

  function visit(node) {
    if (
      ts.isTypeAliasDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === typeName
    ) {
      text = node.type.getText(sourceFile);
      return;
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return text;
}

function propertyNameText(name) {
  if (ts.isIdentifier(name) || ts.isStringLiteralLike(name) || ts.isNumericLiteral(name)) {
    return name.text;
  }
  return undefined;
}

function extractObjectTypePropertiesFromTs(source, declarationName) {
  const sourceFile = ts.createSourceFile('source.ts', source, ts.ScriptTarget.Latest, true);
  let properties;

  function readMembers(members) {
    return members
      .map((member) => {
        const name = propertyNameText(member.name);
        if (!name) return undefined;

        if (ts.isMethodSignature(member)) {
          const parameters = member.parameters.map((parameter) => parameter.getText(sourceFile));
          return {
            name,
            optional: Boolean(member.questionToken),
            type: `(${parameters.join(', ')}) => ${member.type?.getText(sourceFile) ?? 'void'}`,
          };
        }

        if (!ts.isPropertySignature(member)) return undefined;
        return {
          name,
          optional: Boolean(member.questionToken),
          type: member.type?.getText(sourceFile) ?? '',
        };
      })
      .filter(Boolean);
  }

  function visit(node) {
    if (
      ts.isInterfaceDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === declarationName
    ) {
      properties = readMembers(node.members);
      return;
    }
    if (
      ts.isTypeAliasDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === declarationName &&
      ts.isTypeLiteralNode(node.type)
    ) {
      properties = readMembers(node.type.members);
      return;
    }
    if (
      ts.isTypeAliasDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === declarationName &&
      ts.isIntersectionTypeNode(node.type)
    ) {
      const mergedProperties = [];
      for (const typeNode of node.type.types) {
        if (ts.isTypeLiteralNode(typeNode)) {
          mergedProperties.push(...readMembers(typeNode.members));
          continue;
        }
        if (ts.isTypeReferenceNode(typeNode) && ts.isIdentifier(typeNode.typeName)) {
          const referencedProperties = extractObjectTypePropertiesFromTs(
            source,
            typeNode.typeName.text,
          );
          if (Array.isArray(referencedProperties)) {
            mergedProperties.push(...referencedProperties);
          }
        }
      }
      properties = mergedProperties;
      return;
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return properties;
}

function extractCallStringArgumentsFromTs(source, functionName) {
  const sourceFile = ts.createSourceFile(
    'source.tsx',
    source,
    ts.ScriptTarget.Latest,
    true,
    ts.ScriptKind.TSX,
  );
  const calls = [];

  function visit(node) {
    if (
      ts.isCallExpression(node) &&
      ts.isIdentifier(node.expression) &&
      node.expression.text === functionName
    ) {
      calls.push(
        node.arguments.map((argument) =>
          ts.isStringLiteralLike(argument) ? argument.text : undefined,
        ),
      );
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return calls;
}

function numericLiteralValue(node) {
  if (ts.isNumericLiteral(node)) return Number(node.text);
  if (
    ts.isPrefixUnaryExpression(node) &&
    node.operator === ts.SyntaxKind.MinusToken &&
    ts.isNumericLiteral(node.operand)
  ) {
    return -Number(node.operand.text);
  }
  return undefined;
}

function extractMappedNumericArraysFromTs(source, parameterName) {
  const sourceFile = ts.createSourceFile(
    'source.tsx',
    source,
    ts.ScriptTarget.Latest,
    true,
    ts.ScriptKind.TSX,
  );
  const arrays = [];

  function visit(node) {
    if (
      ts.isCallExpression(node) &&
      ts.isPropertyAccessExpression(node.expression) &&
      node.expression.name.text === 'map' &&
      ts.isArrayLiteralExpression(node.expression.expression)
    ) {
      const callback = node.arguments[0];
      const callbackParameter = callback?.parameters?.[0]?.name;
      if (
        callbackParameter &&
        ts.isIdentifier(callbackParameter) &&
        callbackParameter.text === parameterName
      ) {
        arrays.push(
          node.expression.expression.elements.map((element) => numericLiteralValue(element)),
        );
      }
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return arrays;
}

function extractNumericArrayConstantFromTs(source, constantName) {
  const sourceFile = ts.createSourceFile(
    'source.ts',
    source,
    ts.ScriptTarget.Latest,
    true,
    ts.ScriptKind.TS,
  );
  let values = null;

  function unwrapArrayInitializer(node) {
    if (ts.isArrayLiteralExpression(node)) return node;
    if (ts.isAsExpression(node) || ts.isSatisfiesExpression?.(node)) {
      return unwrapArrayInitializer(node.expression);
    }
    return null;
  }

  function visit(node) {
    if (values) return;
    if (
      ts.isVariableDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === constantName
    ) {
      const arrayInitializer = node.initializer ? unwrapArrayInitializer(node.initializer) : null;
      if (arrayInitializer) {
        values = arrayInitializer.elements.map((element) => numericLiteralValue(element));
      }
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return values;
}

function extractNumericObjectKeysForPropertyFromTs(source, propertyName) {
  const sourceFile = ts.createSourceFile(
    'source.tsx',
    source,
    ts.ScriptTarget.Latest,
    true,
    ts.ScriptKind.TSX,
  );
  const keyGroups = [];

  function numericPropertyNameValue(name) {
    const text = propertyNameText(name);
    if (text === undefined || !/^-?\d+$/.test(text)) return undefined;
    return Number(text);
  }

  function visit(node) {
    if (
      ts.isPropertyAssignment(node) &&
      propertyNameText(node.name) === propertyName &&
      ts.isObjectLiteralExpression(node.initializer)
    ) {
      keyGroups.push(
        node.initializer.properties
          .map((property) =>
            ts.isPropertyAssignment(property) ? numericPropertyNameValue(property.name) : undefined,
          )
          .filter((value) => value !== undefined),
      );
    }
    ts.forEachChild(node, visit);
  }

  visit(sourceFile);
  return keyGroups;
}

function parseCsvRows(csv) {
  const rows = [];
  let row = [];
  let cell = '';
  let inQuotes = false;

  for (let index = 0; index < csv.length; index += 1) {
    const character = csv[index];

    if (inQuotes) {
      if (character === '"') {
        if (csv[index + 1] === '"') {
          cell += '"';
          index += 1;
        } else {
          inQuotes = false;
        }
      } else {
        cell += character;
      }
      continue;
    }

    if (character === '"') {
      if (cell.length) {
        throw new Error('unexpected quote inside unquoted cell');
      }
      inQuotes = true;
    } else if (character === ',') {
      row.push(cell);
      cell = '';
    } else if (character === '\n') {
      row.push(cell);
      rows.push(row);
      row = [];
      cell = '';
    } else if (character !== '\r') {
      cell += character;
    }
  }

  if (inQuotes) {
    throw new Error('unterminated quoted cell');
  }
  if (cell.length || row.length) {
    row.push(cell);
    rows.push(row);
  }

  return rows;
}

function questionOptionPayload(question, field) {
  return JSON.stringify(
    question.options.map((option) => ({
      id: option.id,
      text: option[field],
    })),
  );
}

function questionSupplementalSourcePayload(question, field) {
  const sources = Array.isArray(question?.supplementalSources) ? question.supplementalSources : [];
  return sources.map((source) => source?.[field] || '').join('|');
}

function isValmyndighetenVotingRightsSource(source) {
  return (
    isObjectRecord(source) &&
    source.title === EXPECTED_VALMYNDIGHETEN_VOTING_RIGHTS_SOURCE.title &&
    source.publisher === EXPECTED_VALMYNDIGHETEN_VOTING_RIGHTS_SOURCE.publisher &&
    source.url === EXPECTED_VALMYNDIGHETEN_VOTING_RIGHTS_SOURCE.url &&
    source.publishedDate === EXPECTED_VALMYNDIGHETEN_VOTING_RIGHTS_SOURCE.publishedDate &&
    source.retrievedDate === EXPECTED_VALMYNDIGHETEN_VOTING_RIGHTS_SOURCE.retrievedDate
  );
}

function questionHasValmyndighetenVotingRightsSource(question) {
  return (
    Array.isArray(question?.supplementalSources) &&
    question.supplementalSources.some(isValmyndighetenVotingRightsSource)
  );
}

function requiredVotingRightsSupplementalQuestionIds() {
  const ids = new Set(VOTING_RIGHTS_SOURCE_QUESTION_IDS);

  if (!Array.isArray(sourceQuestions) || !Array.isArray(generatedPublishedQuestions)) {
    return ids;
  }

  VOTING_RIGHTS_SOURCE_QUESTION_IDS.forEach((sourceId) => {
    const sourceIndex = sourceQuestions.findIndex((question) => question.id === sourceId);
    if (sourceIndex < 0) return;
    generatedPublishedQuestions
      .slice(
        sourceIndex * GENERATED_VARIANTS_PER_SOURCE,
        (sourceIndex + 1) * GENERATED_VARIANTS_PER_SOURCE,
      )
      .forEach((question) => {
        if (hasText(question?.id)) ids.add(question.id);
      });
  });

  return ids;
}

function optionIdsMatchQuestionType(question) {
  if (!Array.isArray(question.options)) return false;
  const optionIds = question.options.map((option) => option?.id);
  if (question.type === 'single_choice') {
    return arrayEquals(optionIds, SINGLE_CHOICE_OPTION_IDS);
  }
  if (question.type === 'true_false') {
    return arrayEquals(optionIds, TRUE_FALSE_OPTION_IDS);
  }
  return optionIds.every(hasText);
}

function trueFalseOptionLabelsMatchConvention(question) {
  if (question.type !== 'true_false' || !Array.isArray(question.options)) return false;
  const legacyLabels = question.options.map((option) => ({
    id: option.id,
    textSv: option.textSv,
    textEn: option.textEn,
  }));
  return jsonEqual(legacyLabels, TRUE_FALSE_OPTIONS);
}

function validateChapterSchema(chapter, index, seenChapterIds, seenNamesSv, seenNamesEn) {
  const expectedId = `ch${String(index + 1).padStart(2, '0')}`;
  const label = hasText(chapter?.id) ? chapter.id : `chapter[${index}]`;
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  chapterExactSchemaKeyFailures(chapter, label).forEach(reject);

  if (!isObjectRecord(chapter)) return false;

  if (chapter.id !== expectedId) reject(`expected chapter ${expectedId}, found ${chapter.id}`);
  if (hasText(chapter.id) && seenChapterIds.has(chapter.id)) {
    reject(`${label} has duplicate chapter id`);
  }
  if (hasText(chapter.id)) seenChapterIds.add(chapter.id);

  for (const field of ['nameSv', 'nameEn', 'descriptionSv', 'descriptionEn']) {
    if (!hasText(chapter[field])) reject(`${label} missing ${field}`);
    if (hasText(chapter[field]) && !textIsTrimmedSingleSpaced(chapter[field])) {
      reject(`${label} ${field} must be trimmed and single-spaced`);
    }
  }

  if (normalizeComparableText(chapter.nameSv) === normalizeComparableText(chapter.nameEn)) {
    reject(`${label} nameSv and nameEn must be distinct bilingual text`);
  }
  if (
    normalizeComparableText(chapter.descriptionSv) ===
    normalizeComparableText(chapter.descriptionEn)
  ) {
    reject(`${label} descriptionSv and descriptionEn must be distinct bilingual text`);
  }

  const normalizedNameSv = normalizeComparableText(chapter.nameSv);
  if (normalizedNameSv && seenNamesSv.has(normalizedNameSv)) {
    reject(`${label} duplicates Swedish chapter name`);
  }
  if (normalizedNameSv) seenNamesSv.add(normalizedNameSv);

  const normalizedNameEn = normalizeComparableText(chapter.nameEn);
  if (normalizedNameEn && seenNamesEn.has(normalizedNameEn)) {
    reject(`${label} duplicates English chapter name`);
  }
  if (normalizedNameEn) seenNamesEn.add(normalizedNameEn);

  if (!Number.isInteger(chapter.questionCount) || chapter.questionCount < 1) {
    reject(`${label} has invalid questionCount`);
  }

  return valid;
}

function chapterTextFieldsAreNormalized(chapter) {
  return ['id', 'nameSv', 'nameEn', 'descriptionSv', 'descriptionEn'].every((field) =>
    textIsTrimmedSingleSpaced(chapter[field]),
  );
}

function chapterLocalizationEnglishGlossFailures(chapter, label) {
  const failures = [];
  for (const field of ['nameText', 'descriptionText']) {
    const localized = chapter?.[field];
    if (!isObjectRecord(localized)) continue;
    for (const [locale, value] of Object.entries(localized)) {
      if (BASE_CONTENT_LOCALES.has(locale) || typeof value !== 'string') continue;
      for (const { label: patternLabel, pattern } of CHAPTER_LOCALIZATION_ENGLISH_GLOSS_PATTERNS) {
        if (pattern.test(value)) {
          failures.push(`${label}.${field}.${locale} contains bare English ${patternLabel}`);
        }
      }
    }
  }
  return failures;
}

function validateQuestionSchema(question, index) {
  const label = hasText(question?.id) ? question.id : `question[${index}]`;
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  if (!isObjectRecord(question)) {
    reject(`${label} must be a PracticeQuestion object`);
    return false;
  }

  questionExactSchemaKeyFailures(question, label).forEach(reject);

  function requireText(field) {
    if (!hasText(question[field])) {
      reject(`${label} missing ${field}`);
    } else if (!textIsTrimmedSingleSpaced(question[field])) {
      reject(`${label} ${field} must be trimmed and single-spaced`);
    }
  }

  requireText('id');
  if (hasText(question.id) && !/^q\d{3,}$/.test(question.id)) {
    reject(`${label} id must use q### format`);
  }

  for (const field of [
    'questionSv',
    'questionEn',
    'explanationSv',
    'explanationEn',
    'correctOptionId',
    'chapterId',
  ]) {
    requireText(field);
  }

  if (!QUESTION_TYPES.has(question.type)) reject(`${label} has invalid type ${question.type}`);
  if (!DIFFICULTIES.has(question.difficulty)) {
    reject(`${label} has invalid difficulty ${question.difficulty}`);
  }
  if (!REVIEW_STATUSES.has(question.reviewStatus)) {
    reject(`${label} has invalid reviewStatus ${question.reviewStatus}`);
  }
  if (
    normalizeComparableText(question.questionSv) === normalizeComparableText(question.questionEn)
  ) {
    reject(`${label} questionSv and questionEn must be distinct bilingual text`);
  }
  if (
    normalizeComparableText(question.explanationSv) ===
    normalizeComparableText(question.explanationEn)
  ) {
    reject(`${label} explanationSv and explanationEn must be distinct bilingual text`);
  }
  for (const field of ['questionSv', 'questionEn', 'explanationSv', 'explanationEn']) {
    if (hasText(question[field]) && !textHasSentenceEnding(question[field])) {
      reject(`${label} ${field} must end with sentence punctuation`);
    }
  }

  if (!Array.isArray(question.options) || ![2, 4].includes(question.options.length)) {
    reject(`${label} must have 2 or 4 options`);
  } else {
    const optionIds = new Set();
    question.options.forEach((option, optionIndex) => {
      const optionLabel = `${label} option[${optionIndex}]`;
      if (!hasText(option.id)) reject(`${optionLabel} missing id`);
      if (hasText(option.id) && !textIsTrimmedSingleSpaced(option.id)) {
        reject(`${optionLabel} id must be trimmed and single-spaced`);
      }
      if (hasText(option.id) && optionIds.has(option.id)) {
        reject(`${label} has duplicate option id ${option.id}`);
      }
      optionIds.add(option.id);
      if (!hasText(option.textSv)) reject(`${optionLabel} missing textSv`);
      if (!hasText(option.textEn)) reject(`${optionLabel} missing textEn`);
      if (hasText(option.textSv) && !textIsTrimmedSingleSpaced(option.textSv)) {
        reject(`${optionLabel} textSv must be trimmed and single-spaced`);
      }
      if (hasText(option.textEn) && !textIsTrimmedSingleSpaced(option.textEn)) {
        reject(`${optionLabel} textEn must be trimmed and single-spaced`);
      }
      if (!optionTextPairIsTranslatedOrInvariant(option)) {
        reject(`${optionLabel} textSv and textEn must be translated or a short invariant label`);
      }
    });
    findDuplicateOptionTextLabels(question).forEach((duplicate) => {
      reject(`${label} has duplicate ${duplicate.field} option text "${duplicate.label}"`);
    });

    if (!optionIds.has(question.correctOptionId)) {
      reject(`${label} correctOptionId does not match an option`);
    }
    if (question.type === 'single_choice' && question.options.length !== 4) {
      reject(`${label} single_choice questions must have 4 options`);
    }
    if (question.type === 'single_choice' && !optionIdsMatchQuestionType(question)) {
      reject(`${label} single_choice options must use a/b/c/d option ids in order`);
    }
    if (
      question.type === 'true_false' &&
      (question.options.length !== 2 ||
        !optionIdsMatchQuestionType(question) ||
        !['true', 'false'].includes(question.correctOptionId) ||
        !trueFalseOptionLabelsMatchConvention(question))
    ) {
      reject(`${label} true_false questions must use true/false option ids and labels in order`);
    }
  }

  if (!Array.isArray(question.tags) || question.tags.length === 0) {
    reject(`${label} must have at least one tag`);
  } else {
    const tags = new Set();
    question.tags.forEach((tag, tagIndex) => {
      if (!hasText(tag)) reject(`${label} tag[${tagIndex}] is blank`);
      if (hasText(tag) && !isSlugTag(tag)) {
        reject(`${label} tag[${tagIndex}] must use lowercase kebab-case`);
      }
      if (hasText(tag) && tags.has(tag)) reject(`${label} has duplicate tag ${tag}`);
      tags.add(tag);
    });
  }

  if (findQuestionStateWelfareEnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted state-welfare English wording`);
  }
  if (findQuestionOlderSickEnglishNaturalnessIssue(question)) {
    reject(`${label} uses literal older-and-sick English wording`);
  }
  if (findQuestionLuciaExplanationRoleScaffoldIssue(question)) {
    reject(`${label} uses Lucia role-scaffold explanation wording`);
  }
  if (findQuestionUmeaDemonymSwedishNaturalnessIssue(question)) {
    reject(`${label} uses nonstandard Umeå demonym Swedish wording`);
  }
  if (findQuestionQ071SocialInsuranceOverlapIssue(question)) {
    reject(`${label} overlaps q071/q156 state-welfare source coverage`);
  }
  if (findQuestionTraditionCommonToDoEnglishIssue(question)) {
    reject(`${label} uses literal common-to-do English wording`);
  }
  if (findQuestionMayDayEnglishNaturalnessIssue(question)) {
    reject(`${label} uses literal First of May English wording`);
  }
  if (findQuestionReferendumAdvisorySwedishNaturalnessIssue(question)) {
    reject(`${label} uses ambiguous advisory-referendum Swedish wording`);
  }
  if (findQuestionGoodFridayEnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted Good Friday English wording`);
  }
  if (findQuestionCouncilOfEuropeWorkForEnglishNaturalnessIssue(question)) {
    reject(`${label} uses literal Council of Europe work-for English wording`);
  }
  if (findQuestionSaltsjobadenEnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted Saltsjöbaden Agreement English wording`);
  }
  if (findQuestionReligiousFreedom1951EnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted 1951 religious-freedom English wording`);
  }
  if (findQuestionRuleOfLawEnglishNaturalnessIssue(question)) {
    reject(`${label} uses literal legal certainty English for rättssäkerhet`);
  }
  if (findQuestionPublicSectorEnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted public-sector English wording`);
  }
  if (findQuestionLargestLakesEnglishNaturalnessIssue(question)) {
    reject(`${label} uses stilted largest-lakes English wording`);
  }
  if (findQuestionReligiousFreedomOptionParallelismIssue(question)) {
    reject(`${label} uses nonparallel religious-freedom option wording`);
  }
  const answerKeyPromptIssue = findQuestionAnswerKeyPromptIssue(question);
  if (answerKeyPromptIssue) reject(answerKeyPromptIssue);
  if (findQuestionTaxVatTwoConceptIssue(question)) {
    reject(`${label} combines tax liability and VAT purchase taxation in one learner-facing item`);
  }
  if (findQuestionQ038OldVatDistractorIssue(question)) {
    reject(`${label} uses the old q038 VAT distractor wording`);
  }
  if (findQuestionSecretBallotSingularSwedishIssue(question)) {
    reject(`${label} uses unnatural secret-ballot Swedish voting pronoun`);
  }
  if (findQuestionGeneratedTrueFalseNaturalnessIssue(question)) {
    reject(`${label} contains a generated true/false grammar-splice stem`);
  }

  if (question.uhrReference && typeof question.uhrReference === 'object') {
    for (const field of ['chapter', 'section']) {
      if (
        hasText(question.uhrReference[field]) &&
        !textIsTrimmedSingleSpaced(question.uhrReference[field])
      ) {
        reject(`${label} uhrReference.${field} must be trimmed and single-spaced`);
      }
    }
  }

  if (question.supplementalSources !== undefined) {
    if (!Array.isArray(question.supplementalSources) || question.supplementalSources.length === 0) {
      reject(`${label} supplementalSources must be a non-empty OfficialSourceReference array`);
    } else {
      question.supplementalSources.forEach((source, sourceIndex) => {
        const sourceLabel = `${label} supplementalSources[${sourceIndex}]`;
        if (!isObjectRecord(source)) {
          reject(`${sourceLabel} must be an OfficialSourceReference object`);
          return;
        }
        for (const field of ['title', 'publisher', 'url', 'retrievedDate']) {
          if (!hasText(source[field])) {
            reject(`${sourceLabel} missing ${field}`);
          } else if (!textIsTrimmedSingleSpaced(source[field])) {
            reject(`${sourceLabel} ${field} must be trimmed and single-spaced`);
          }
        }
        if (source.publishedDate !== undefined && !hasText(source.publishedDate)) {
          reject(`${sourceLabel} publishedDate must not be blank when present`);
        }
        if (hasText(source.url) && !isHttpsUrl(source.url)) {
          reject(`${sourceLabel} url must be HTTPS`);
        }
        for (const field of ['publishedDate', 'retrievedDate']) {
          if (source[field] !== undefined && !isIsoDate(source[field])) {
            reject(`${sourceLabel} ${field} must use YYYY-MM-DD`);
          }
        }
      });
    }
  }

  if (
    requiredVotingRightsSupplementalQuestionIds().has(question.id) &&
    !questionHasValmyndighetenVotingRightsSource(question)
  ) {
    reject(`${label} voting-rights question must cite Valmyndigheten as a supplemental source`);
  }

  return valid;
}

