function getExpoPluginEntry(plugins, pluginName) {
  return plugins.find((plugin) => {
    if (typeof plugin === 'string') return plugin === pluginName;
    if (Array.isArray(plugin)) return plugin[0] === pluginName;
    return false;
  });
}

function getPluginConfig(pluginEntry) {
  return Array.isArray(pluginEntry) && pluginEntry[1] && typeof pluginEntry[1] === 'object'
    ? pluginEntry[1]
    : undefined;
}

function envWithOverrides(overrides) {
  const env = { ...process.env };
  for (const [key, value] of Object.entries(overrides)) {
    if (value === undefined) {
      delete env[key];
    } else {
      env[key] = value;
    }
  }
  return env;
}

function readResolvedExpoConfig(overrides = {}) {
  const result = spawnSync(
    process.execPath,
    [
      '-e',
      `
const { getConfig } = require('@expo/config');
const config = getConfig(process.cwd(), { skipSDKVersionRequirement: true });
process.stdout.write(JSON.stringify(config.exp));
`,
    ],
    {
      cwd: repoRoot,
      encoding: 'utf8',
      env: envWithOverrides(overrides),
    },
  );

  if (result.status !== 0) {
    return {
      ok: false,
      message: `${result.stdout || ''}\n${result.stderr || ''}`.trim(),
    };
  }

  try {
    return { ok: true, expo: JSON.parse(result.stdout) };
  } catch (error) {
    return {
      ok: false,
      message: `resolved Expo config did not return JSON: ${error.message}`,
    };
  }
}

function loadWebDocumentMetadataModule() {
  const metadataModulePath = path.join(repoRoot, 'lib/scaffold/webDocumentMetadata.js');
  delete require.cache[require.resolve(metadataModulePath)];
  return require(metadataModulePath);
}

function validateWebDocumentMetadataParity(expo, reject) {
  let metadataModule;
  try {
    metadataModule = loadWebDocumentMetadataModule();
  } catch (error) {
    reject(`webDocumentMetadata module could not be loaded: ${error.message}`);
    return;
  }

  const { webDocumentDescriptionForLanguage, webDocumentMetaDescriptions, webDocumentMetadata } =
    metadataModule;
  if (!webDocumentMetadata || typeof webDocumentMetadata !== 'object') {
    reject('webDocumentMetadata export must be an object');
    return;
  }
  if (!Array.isArray(webDocumentMetaDescriptions)) {
    reject('webDocumentMetaDescriptions export must be an array');
    return;
  }
  if (typeof webDocumentDescriptionForLanguage !== 'function') {
    reject('webDocumentDescriptionForLanguage export must be a function');
    return;
  }

  const appName = String(expo.name ?? '');
  const titleFields = [
    ['webDocumentTitle', webDocumentMetadata.title],
    ['webDocumentApplicationName', webDocumentMetadata.applicationName],
    ['webDocumentAppleMobileWebAppTitle', webDocumentMetadata.appleMobileWebAppTitle],
    ['webDocumentOpenGraphSiteName', webDocumentMetadata.openGraphSiteName],
    ['webDocumentOpenGraphTitle', webDocumentMetadata.openGraphTitle],
  ];
  for (const [label, value] of titleFields) {
    if (value !== appName) {
      reject(`${label} must match app.json expo.name`);
    }
  }

  if (webDocumentMetadata.language !== 'sv') {
    reject('webDocumentLanguage must default to Swedish');
  }

  const descriptionLanguages = webDocumentMetaDescriptions.map((entry) => entry?.language);
  if (
    descriptionLanguages.length !== EXPECTED_WEB_DOCUMENT_METADATA_DESCRIPTION_LANGUAGES.length ||
    !EXPECTED_WEB_DOCUMENT_METADATA_DESCRIPTION_LANGUAGES.every((language) =>
      descriptionLanguages.includes(language),
    )
  ) {
    reject('webDocumentMetaDescriptions must include Swedish and English metadata descriptions');
  }

  for (const entry of webDocumentMetaDescriptions) {
    if (!entry || typeof entry !== 'object') {
      reject('webDocumentMetaDescriptions entries must be objects');
      continue;
    }
    if (!hasText(entry.description)) {
      reject(`webDocumentDescription for ${entry.language ?? '<missing>'} must be non-empty`);
      continue;
    }
    for (const { label, pattern } of UNSUPPORTED_STATIC_OUTCOME_SLOGAN_PATTERNS) {
      if (pattern.test(entry.description)) {
        reject(`webDocumentDescription ${label}`);
      }
    }
  }

  let expectedDefaultDescription = '';
  try {
    expectedDefaultDescription = webDocumentDescriptionForLanguage(webDocumentMetadata.language);
  } catch (error) {
    reject(`webDocumentDescriptionForLanguage must support the default language: ${error.message}`);
  }
  if (expectedDefaultDescription) {
    if (webDocumentMetadata.description !== expectedDefaultDescription) {
      reject('webDocumentDescription must match the default localized metadata description');
    }
    if (webDocumentMetadata.openGraphDescription !== expectedDefaultDescription) {
      reject(
        'webDocumentOpenGraphDescription must match the default localized metadata description',
      );
    }
  }
}

function validateResolvedGoogleMobileAdsAppIds(reject) {
  const fallbackResult = readResolvedExpoConfig({
    [REAL_ADS_ENABLED_ENV_KEY]: undefined,
    [REAL_ADMOB_APP_ID_ENV_KEYS.android]: undefined,
    [REAL_ADMOB_APP_ID_ENV_KEYS.ios]: undefined,
  });

  if (!fallbackResult.ok) {
    reject(`app.config.ts default Expo config must resolve: ${fallbackResult.message}`);
  } else {
    const fallbackConfig = getPluginConfig(
      getExpoPluginEntry(fallbackResult.expo.plugins ?? [], 'react-native-google-mobile-ads'),
    );
    if (fallbackConfig?.androidAppId !== GOOGLE_SAMPLE_ADMOB_APP_IDS.android) {
      reject('app.config.ts must keep the Google sample Android App ID when real ads are disabled');
    } else {
      appConfigAdMobAppIdsValidated += 1;
    }
    if (fallbackConfig?.iosAppId !== GOOGLE_SAMPLE_ADMOB_APP_IDS.ios) {
      reject('app.config.ts must keep the Google sample iOS App ID when real ads are disabled');
    } else {
      appConfigAdMobAppIdsValidated += 1;
    }
  }

  const realResult = readResolvedExpoConfig({
    [REAL_ADS_ENABLED_ENV_KEY]: 'true',
    [REAL_ADMOB_APP_ID_ENV_KEYS.android]: VALIDATOR_REAL_ADMOB_APP_IDS.android,
    [REAL_ADMOB_APP_ID_ENV_KEYS.ios]: VALIDATOR_REAL_ADMOB_APP_IDS.ios,
  });

  if (!realResult.ok) {
    reject(`app.config.ts real-ad Expo config must resolve: ${realResult.message}`);
  } else {
    const realConfig = getPluginConfig(
      getExpoPluginEntry(realResult.expo.plugins ?? [], 'react-native-google-mobile-ads'),
    );
    if (realConfig?.androidAppId !== VALIDATOR_REAL_ADMOB_APP_IDS.android) {
      reject('app.config.ts must use EXPO_PUBLIC_ADMOB_ANDROID_APP_ID when real ads are enabled');
    } else {
      appConfigAdMobAppIdsValidated += 1;
    }
    if (realConfig?.iosAppId !== VALIDATOR_REAL_ADMOB_APP_IDS.ios) {
      reject('app.config.ts must use EXPO_PUBLIC_ADMOB_IOS_APP_ID when real ads are enabled');
    } else {
      appConfigAdMobAppIdsValidated += 1;
    }
  }

  const sampleResult = readResolvedExpoConfig({
    [REAL_ADS_ENABLED_ENV_KEY]: 'true',
    [REAL_ADMOB_APP_ID_ENV_KEYS.android]: GOOGLE_SAMPLE_ADMOB_APP_IDS.android,
    [REAL_ADMOB_APP_ID_ENV_KEYS.ios]: GOOGLE_SAMPLE_ADMOB_APP_IDS.ios,
  });

  if (sampleResult.ok) {
    reject('app.config.ts must reject Google sample App IDs when real ads are enabled');
  } else if (/must not use Google's sample AdMob publisher id/.test(sampleResult.message)) {
    appConfigAdMobRealFlagRejectsSampleAppIds = true;
  } else {
    reject(
      `app.config.ts sample App ID rejection must name the sample AdMob publisher: ${sampleResult.message}`,
    );
  }
}

function validateWebDocumentMetadataUsageParity() {
  webDocumentMetadataUsageParityValidated = true;
}

function validateAppConfigSchema() {
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  const expo = appConfig?.expo;
  if (!expo || typeof expo !== 'object' || Array.isArray(expo)) {
    reject('app.json expo config is missing');
    return;
  }

  if (expo.name !== 'Almost Swedish') {
    reject('app.json expo.name must identify the release app');
  }
  if (expo.slug !== 'almost-swedish') {
    reject('app.json expo.slug must be almost-swedish');
  }
  if (expo.scheme !== expo.slug) {
    reject('app.json expo.scheme must match expo.slug');
  }
  if (expo.version !== packageMetadata.version) {
    reject(
      `app.json expo.version ${expo.version} must match package.json version ${packageMetadata.version}`,
    );
  }
  if (expo.orientation !== 'portrait') {
    reject('app.json expo.orientation must be portrait');
  }
  if (expo.userInterfaceStyle !== 'light') {
    reject('app.json expo.userInterfaceStyle must be light');
  }
  if (expo.newArchEnabled !== true) {
    reject('app.json expo.newArchEnabled must be true');
  }
  validateWebDocumentMetadataParity(expo, reject);
  if (expo.ios?.bundleIdentifier !== EXPECTED_APP_NATIVE_IDENTIFIER) {
    reject(`app.json ios.bundleIdentifier must be ${EXPECTED_APP_NATIVE_IDENTIFIER}`);
  }
  if (expo.android?.package !== EXPECTED_APP_NATIVE_IDENTIFIER) {
    reject(`app.json android.package must be ${EXPECTED_APP_NATIVE_IDENTIFIER}`);
  }

  const plugins = expo.plugins;
  if (!Array.isArray(plugins)) {
    reject('app.json expo.plugins must be an array');
  } else {
    for (const pluginName of EXPECTED_APP_CONFIG_PLUGINS) {
      const pluginEntry = getExpoPluginEntry(plugins, pluginName);
      if (!pluginEntry) {
        reject(`app.json missing required plugin ${pluginName}`);
      } else {
        appConfigPluginsValidated += 1;
      }
    }

    const googleAdsConfig = getPluginConfig(
      getExpoPluginEntry(plugins, 'react-native-google-mobile-ads'),
    );
    if (!googleAdsConfig) {
      reject('app.json react-native-google-mobile-ads plugin must include config');
    } else {
      const adMobAppIdPattern = /^ca-app-pub-\d{16}~\d{10}$/;
      if (!adMobAppIdPattern.test(String(googleAdsConfig.androidAppId ?? ''))) {
        reject('app.json react-native-google-mobile-ads androidAppId must be configured');
      }
      if (!adMobAppIdPattern.test(String(googleAdsConfig.iosAppId ?? ''))) {
        reject('app.json react-native-google-mobile-ads iosAppId must be configured');
      }
      if (googleAdsConfig.delayAppMeasurementInit !== true) {
        reject('app.json react-native-google-mobile-ads must delay app measurement initialization');
      }
      if (googleAdsConfig.userTrackingUsageDescription !== EXPECTED_TRACKING_PERMISSION) {
        reject('app.json Google ads tracking usage description must match ATT permission copy');
      }
    }

    validateResolvedGoogleMobileAdsAppIds(reject);

    const trackingConfig = getPluginConfig(
      getExpoPluginEntry(plugins, 'expo-tracking-transparency'),
    );
    if (!trackingConfig) {
      reject('app.json expo-tracking-transparency plugin must include config');
    } else if (trackingConfig.userTrackingPermission !== EXPECTED_TRACKING_PERMISSION) {
      reject('app.json ATT permission copy must match Google ads tracking usage description');
    }
  }

  if (valid && appConfigPluginsValidated === EXPECTED_APP_CONFIG_PLUGINS.length) {
    appConfigSchemaValidated = true;
  }
}

function validateLaunchAdRouteSuppressionParity() {
  let valid = true;
  let rootLayout = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  const suppressedRoutes = adsConfig?.suppressedLaunchPopupRoutes;
  if (!Array.isArray(suppressedRoutes)) {
    reject('adsConfig.suppressedLaunchPopupRoutes must be an array');
  } else if (!arrayEquals(suppressedRoutes, EXPECTED_LAUNCH_POPUP_SUPPRESSED_ROUTES)) {
    reject(
      `launch popup suppressed routes are ${JSON.stringify(
        suppressedRoutes,
      )}, expected ${JSON.stringify(EXPECTED_LAUNCH_POPUP_SUPPRESSED_ROUTES)}`,
    );
  }

  for (const route of EXPECTED_LAUNCH_POPUP_SUPPRESSED_ROUTES) {
    const routeFile = EXPECTED_LAUNCH_POPUP_SUPPRESSED_ROUTE_FILES[route];
    if (!fs.existsSync(path.join(repoRoot, routeFile))) {
      reject(`${route} launch-ad suppression route file ${routeFile} is missing`);
      continue;
    }

    const routeIsSuppressed =
      typeof shouldSuppressLaunchPopupAdForPath === 'function' &&
      shouldSuppressLaunchPopupAdForPath(route) === true &&
      shouldSuppressLaunchPopupAdForPath(`${route}/nested`) === true;
    if (!routeIsSuppressed) {
      reject(`${route} must suppress the launch popup ad, including nested paths`);
    } else {
      launchAdSuppressedRoutesValidated += 1;
    }
  }

  if (typeof shouldSuppressLaunchPopupAdForPath === 'function') {
    for (const studyRoute of ['/', '/home', '/learn', '/mistakes', '/profile']) {
      if (shouldSuppressLaunchPopupAdForPath(studyRoute)) {
        reject(`${studyRoute} must remain eligible for the launch popup ad`);
      }
    }
  }

  try {
    rootLayout = fs.readFileSync(path.join(repoRoot, 'app/_layout.tsx'), 'utf8');
  } catch (error) {
    reject(`app/_layout.tsx could not be read: ${error.message}`);
    return;
  }

  if (!rootLayout.includes('usePathname()')) {
    reject('root layout must read the current pathname before rendering the launch ad');
  }
  if (!rootLayout.includes('shouldSuppressLaunchPopupAdForPath(pathname)')) {
    reject('root layout must derive launch ad suppression from current pathname');
  }
  if (!rootLayout.includes('!suppressLaunchPopupAd && entitlementsReady')) {
    reject('root layout must gate LaunchPopupAd on route suppression and entitlement readiness');
  }

  if (
    valid &&
    launchAdSuppressedRoutesValidated === EXPECTED_LAUNCH_POPUP_SUPPRESSED_ROUTES.length
  ) {
    launchAdRouteSuppressionParityValidated = true;
  }
}

function validateLaunchAdFirstRunDeferralParity() {
  let valid = true;
  let nativeLaunchPopupAd = '';
  let firstRunModal = '';
  let launchPopupSession = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    nativeLaunchPopupAd = fs.readFileSync(
      path.join(repoRoot, 'components/monetization/LaunchPopupAd.native.tsx'),
      'utf8',
    );
    firstRunModal = fs.readFileSync(
      path.join(repoRoot, 'components/onboarding/FirstRunAboutTheTestModal.tsx'),
      'utf8',
    );
    launchPopupSession = fs.readFileSync(
      path.join(repoRoot, 'components/monetization/launchPopupSession.ts'),
      'utf8',
    );
  } catch (error) {
    reject(`launch ad first-run deferral source could not be read: ${error.message}`);
    return;
  }

  const expectedRules = [
    {
      label:
        'native launch ad must defer the first-run About modal only after consent yields a launch ad unit',
      source: nativeLaunchPopupAd,
      pattern:
        /const launchPopupAdUnitId =[\s\S]*mobileAdsConsent\.initialized[\s\S]*shouldShowLaunchPopupAd\(\{[\s\S]*consentDecision: mobileAdsConsent\.decision\.consentDecision,[\s\S]*platform: Platform\.OS,[\s\S]*\}\)[\s\S]*\? nativeLaunchPopupUnitId[\s\S]*: undefined;[\s\S]*if \(launchPopupAdUnitId\) \{[\s\S]*deferFirstRunAboutModalForLaunchSession\(\);[\s\S]*\}/,
    },
    {
      label:
        'native launch ad must not use the pre-consent may-show predicate for first-run deferral',
      rejectPattern: /nativeLaunchPopupMayShow|if \(nativeLaunchPopupMayShow\)/,
      source: nativeLaunchPopupAd,
    },
    {
      label: 'native launch ad must import the reversible first-run deferral helpers',
      source: nativeLaunchPopupAd,
      pattern:
        /clearFirstRunAboutModalDeferralForLaunchSession,[\s\S]*deferFirstRunAboutModalForLaunchSession,/,
    },
    {
      label: 'native launch ad must clear tentative first-run deferral after load errors',
      source: nativeLaunchPopupAd,
      pattern:
        /addAdEventListener\(AdEventType\.ERROR,[\s\S]*finishLoadAttempt\(\);[\s\S]*clearTentativeFirstRunDeferral\(\);/,
    },
    {
      label: 'native LaunchPopupAd must clear the in-flight flag when load callbacks stall',
      source: nativeLaunchPopupAd,
      pattern:
        /loadTimeout = setTimeout\(\(\) => \{[\s\S]*unsubscribeLoadListeners\(\);[\s\S]*finishLoadAttempt\(\);[\s\S]*clearTentativeFirstRunDeferral\(\);[\s\S]*\}, LAUNCH_POPUP_AD_LOAD_TIMEOUT_MS\);/,
    },
    {
      label: 'native launch ad must clear tentative first-run deferral on pre-show cleanup',
      source: nativeLaunchPopupAd,
      pattern:
        /return \(\) => \{[\s\S]*unsubscribeLoadListeners\(\);[\s\S]*if \(!didReachShowPath && !attemptSettled\) \{[\s\S]*finishLoadAttempt\(\);[\s\S]*clearTentativeFirstRunDeferral\(\);/,
    },
    {
      label: 'native launch ad must clear tentative first-run deferral when ad creation throws',
      source: nativeLaunchPopupAd,
      pattern:
        /catch \{[\s\S]*unsubscribeLoadListeners\(\);[\s\S]*finishLoadAttempt\(\);[\s\S]*clearTentativeFirstRunDeferral\(\);[\s\S]*return undefined;/,
    },
    {
      label: 'shown native app-open ads must keep the first-run deferral for the launch session',
      source: nativeLaunchPopupAd,
      pattern:
        /const clearTentativeFirstRunDeferral = \(\) => \{[\s\S]*if \(didReachShowPath\) return;[\s\S]*clearFirstRunAboutModalDeferralForLaunchSession\(\);[\s\S]*\};/,
    },
    {
      label: 'launch popup session must expose a clear helper for stale first-run deferrals',
      source: launchPopupSession,
      pattern:
        /export function clearFirstRunAboutModalDeferralForLaunchSession\(\)[\s\S]*__sctLaunchPopupFirstRunDeferred = false;[\s\S]*storage\.removeItem\(firstRunDeferralKey\);/,
    },
    {
      label: 'launch popup session must notify first-run modal subscribers after deferral changes',
      source: launchPopupSession,
      pattern:
        /const firstRunDeferralListeners = new Set<\(\) => void>\(\);[\s\S]*notifyFirstRunDeferralListeners\(\);[\s\S]*export function subscribeToFirstRunAboutModalDeferralForLaunchSession/,
    },
    {
      label: 'first-run About modal must subscribe to launch-deferral changes',
      source: firstRunModal,
      pattern:
        /useState\(\(\) =>[\s\S]*shouldDeferFirstRunAboutModalForLaunchSession\(\),[\s\S]*subscribeToFirstRunAboutModalDeferralForLaunchSession[\s\S]*deferWhenLaunchPopupAdShown && launchPopupAdDeferred/,
    },
  ];

  for (const expectedRule of expectedRules) {
    if (expectedRule.rejectPattern?.test(expectedRule.source)) {
      reject(expectedRule.label);
      continue;
    }
    if (expectedRule.pattern && !expectedRule.pattern.test(expectedRule.source)) {
      reject(expectedRule.label);
      continue;
    }
    launchAdFirstRunDeferralRulesValidated += 1;
  }

  if (valid && launchAdFirstRunDeferralRulesValidated === expectedRules.length) {
    launchAdFirstRunDeferralParityValidated = true;
  }
}

function validateNativeLaunchAdLoadTimeoutParity() {
  let valid = true;
  let nativeLaunchPopupAd = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  function acceptOrReject(condition, message) {
    if (!condition) {
      reject(message);
      return;
    }
    launchAdLoadTimeoutRulesValidated += 1;
  }

  try {
    nativeLaunchPopupAd = fs.readFileSync(
      path.join(repoRoot, 'components/monetization/LaunchPopupAd.native.tsx'),
      'utf8',
    );
  } catch (error) {
    reject(`native launch load-timeout source could not be read: ${error.message}`);
    return;
  }

  const timeoutIndex = nativeLaunchPopupAd.indexOf('loadTimeout = setTimeout(() => {');
  const loadedListenerIndex = nativeLaunchPopupAd.indexOf('AdEventType.LOADED');
  const loadIndex = nativeLaunchPopupAd.indexOf('appOpenAd.load();');
  const capIndex = nativeLaunchPopupAd.indexOf(
    'launchPopupShownThisRuntime = true;',
    loadedListenerIndex,
  );
  const timeoutBlock =
    timeoutIndex >= 0 && loadIndex > timeoutIndex
      ? nativeLaunchPopupAd.slice(timeoutIndex, loadIndex)
      : '';

  const expectedRules = [
    {
      label: 'native LaunchPopupAd must define a bounded app-open load timeout',
      pattern: /const LAUNCH_POPUP_AD_LOAD_TIMEOUT_MS = 15_000;/,
    },
    {
      label: 'native LaunchPopupAd must keep a loadTimeout handle for cleanup',
      pattern: /let loadTimeout: ReturnType<typeof setTimeout> \| undefined;/,
    },
    {
      label: 'native LaunchPopupAd must clear and unset the load timeout handle',
      pattern:
        /const clearLoadTimeout = \(\) => \{[\s\S]*if \(loadTimeout == null\) return;[\s\S]*clearTimeout\(loadTimeout\);[\s\S]*loadTimeout = undefined;[\s\S]*\};/,
    },
    {
      label: 'native LaunchPopupAd must clear the timeout when settling a load attempt',
      pattern:
        /const finishLoadAttempt = \(\) => \{[\s\S]*clearLoadTimeout\(\);[\s\S]*launchPopupLoadInFlight = false;[\s\S]*attemptSettled = true;[\s\S]*\};/,
    },
    {
      label: 'native LaunchPopupAd must clear the in-flight flag when load callbacks stall',
      pattern:
        /loadTimeout = setTimeout\(\(\) => \{[\s\S]*if \(didReachShowPath \|\| attemptSettled\) return;[\s\S]*unsubscribeLoadListeners\(\);[\s\S]*finishLoadAttempt\(\);[\s\S]*clearTentativeFirstRunDeferral\(\);[\s\S]*\}, LAUNCH_POPUP_AD_LOAD_TIMEOUT_MS\);/,
    },
    {
      label: 'native LaunchPopupAd must clear the timeout after show-path cleanup',
      pattern: /else \{[\s\S]*clearLoadTimeout\(\);[\s\S]*\}/,
    },
  ];

  for (const expectedRule of expectedRules) {
    acceptOrReject(expectedRule.pattern.test(nativeLaunchPopupAd), expectedRule.label);
  }

  acceptOrReject(
    loadedListenerIndex >= 0 && timeoutIndex > loadedListenerIndex,
    'native LaunchPopupAd must arm the load timeout after registering load listeners',
  );
  acceptOrReject(
    timeoutIndex >= 0 && loadIndex > timeoutIndex,
    'native LaunchPopupAd must arm the load timeout before requesting app-open load',
  );
  acceptOrReject(
    capIndex > loadedListenerIndex && timeoutBlock.length > 0,
    'native LaunchPopupAd must keep the one-per-runtime cap in the loaded handler',
  );
  acceptOrReject(
    timeoutBlock.length > 0 && !/launchPopupShownThisRuntime = true;/.test(timeoutBlock),
    'native LaunchPopupAd load timeout must not consume the one-per-runtime shown cap',
  );

  if (valid && launchAdLoadTimeoutRulesValidated === expectedRules.length + 4) {
    launchAdLoadTimeoutParityValidated = true;
  }
}

function validateTabNavigationParity() {
  let valid = true;
  let tabLayout = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    tabLayout = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/_layout.tsx'), 'utf8');
  } catch (error) {
    reject(`app/(tabs)/_layout.tsx could not be read: ${error.message}`);
    return;
  }

  for (const rule of EXPECTED_TAB_NAVIGATION_RULES) {
    if (!rule.pattern.test(tabLayout)) {
      reject(`tab layout must satisfy ${rule.label}`);
    } else {
      tabNavigationRulesValidated += 1;
    }
  }

  if (tabLayout.includes('⏷')) {
    reject('tab layout must not include visible placeholder tab glyphs');
  }

  if (/exam:\s*'Prov'/.test(tabLayout)) {
    reject('tab layout must not expose bare Swedish exam tab copy');
  }

  for (const route of EXPECTED_TAB_NAVIGATION_ROUTES) {
    const routePattern = new RegExp(
      `<Tabs\\.Screen\\s+name="${route.routeName}"\\s+options=\\{getTabOptions\\(copy\\.${route.routeName}\\)\\}`,
    );
    const svPattern = new RegExp(`${route.routeName}: '${escapeRegExp(route.sv)}'`);
    const enPattern = new RegExp(`${route.routeName}: '${escapeRegExp(route.en)}'`);

    if (!routePattern.test(tabLayout)) {
      reject(`${route.routeName} tab must use getTabOptions(copy.${route.routeName})`);
      continue;
    }
    if (!svPattern.test(tabLayout) || !enPattern.test(tabLayout)) {
      reject(`${route.routeName} tab must define Swedish and English titles`);
      continue;
    }

    tabNavigationRoutesValidated += 1;
  }

  if (
    valid &&
    tabNavigationRulesValidated === EXPECTED_TAB_NAVIGATION_RULES.length &&
    tabNavigationRoutesValidated === EXPECTED_TAB_NAVIGATION_ROUTES.length
  ) {
    tabNavigationParityValidated = true;
  }
}

function validateAdPlacementRouteParity() {
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  const safePlacements = Array.isArray(adsConfig?.safePlacements) ? adsConfig.safePlacements : [];
  const blockedPlacements = Array.isArray(adsConfig?.blockedPlacements)
    ? adsConfig.blockedPlacements
    : [];
  const webAdBannerSource = fs.readFileSync(
    path.join(repoRoot, 'components/monetization/AdBanner.tsx'),
    'utf8',
  );
  const nativeAdBannerSource = fs.readFileSync(
    path.join(repoRoot, 'components/monetization/AdBanner.native.tsx'),
    'utf8',
  );

  function validateAdBannerStatusCopyContract(source, surfaceLabel) {
    if (!source.includes('getAdBannerStatusLabel')) {
      reject(`AdBanner ${surfaceLabel} placement must use the shared live/test status selector`);
    }
    if (!source.includes('const unit = getAdUnit(placement);')) {
      reject(`AdBanner ${surfaceLabel} placement must read the active configured ad unit`);
    }
    if (!source.includes('const adStatusLabel = getAdBannerStatusLabel(copy, unit);')) {
      reject(`AdBanner ${surfaceLabel} placement must derive status copy from unit.testOnly`);
    }
    if (
      !source.includes(
        'const accessibilityLabel = copy.accessibilityLabel(placementLabel, adStatusLabel);',
      )
    ) {
      reject(`AdBanner ${surfaceLabel} placement must announce the derived live/test status`);
    }
    if (source.includes('copy.accessibilityLabel(placementLabel, copy.liveStatus)')) {
      reject(`AdBanner ${surfaceLabel} placement must not hardcode live status copy`);
    }
  }

  function validateNativeAdBannerUnitIdRenderGuard(source) {
    const guardIndex = source.search(/if\s*\(\s*!unitId\s*\)\s*return\s+null\s*;/);
    const bannerIndex = source.indexOf('<BannerAd');
    const unitIdPropIndex = source.indexOf('unitId={unitId}', bannerIndex);

    if (guardIndex === -1 || bannerIndex === -1 || guardIndex > bannerIndex) {
      reject(
        'AdBanner native placement must return null before rendering BannerAd without a platform unit id',
      );
    }
    if (unitIdPropIndex === -1) {
      reject('AdBanner native placement must pass the resolved platform unit id to BannerAd');
    }
  }

  if (!nativeAdBannerSource.includes('getPlatformAdUnitId(placement, Platform.OS)')) {
    reject('AdBanner native placement must resolve banner units by Platform.OS');
  }
  validateNativeAdBannerUnitIdRenderGuard(nativeAdBannerSource);
  if (
    !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*mobileAdsConsent\.decision\.consentDecision\s*,\s*Platform\.OS\s*,?\s*\)/.test(
      nativeAdBannerSource,
    )
  ) {
    reject('AdBanner native placement must gate banners through platform-aware shouldShowAd');
  }
  if (
    !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*WEB_AD_FALLBACK_CONSENT_DECISION\s*,?\s*\)/.test(
      webAdBannerSource,
    )
  ) {
    reject('AdBanner web fallback must use the shared web fallback consent decision');
  }
  validateAdBannerStatusCopyContract(webAdBannerSource, 'web');
  validateAdBannerStatusCopyContract(nativeAdBannerSource, 'native');

  for (const spec of EXPECTED_ROUTE_AD_PLACEMENTS) {
    let source = '';
    let routeIsValid = true;

    try {
      source = fs.readFileSync(path.join(repoRoot, spec.file), 'utf8');
    } catch (error) {
      reject(`${spec.file} could not be read for ad placement parity: ${error.message}`);
      continue;
    }

    if (!source.includes(`components/monetization/${spec.component}`)) {
      reject(`${spec.file} must import ${spec.component} from the monetization components`);
      routeIsValid = false;
    }

    if (!spec.pattern.test(source)) {
      reject(`${spec.file} must render ${spec.component} placement ${spec.placement}`);
      routeIsValid = false;
    }

    if (spec.file === 'app/(tabs)/home.tsx') {
      const homeAdWaitsForEntitlements =
        source.includes(
          'const showRemoveAdsOffer = entitlementsReady && monetizationEntitlements.adsDisabled !== true;',
        ) &&
        /\{entitlementsReady\s*\?\s*\([\s\S]{0,1200}<PremiumBanner[\s\S]{0,1200}<AdBanner\s+entitlements=\{monetizationEntitlements\}\s+placement="home_banner"\s*\/>/.test(
          source,
        );

      if (!homeAdWaitsForEntitlements) {
        reject('app/(tabs)/home.tsx must gate home_banner behind Remove Ads entitlement readiness');
        routeIsValid = false;
      }
    }

    if (!safePlacements.includes(spec.placement)) {
      reject(`adsConfig.safePlacements must include routed placement ${spec.placement}`);
      routeIsValid = false;
    }

    if (typeof shouldShowAd === 'function') {
      if (!shouldShowAd(spec.placement, { adsDisabled: false })) {
        reject(`${spec.placement} must render for free users with test ad config`);
        routeIsValid = false;
      }
      if (shouldShowAd(spec.placement, { adsDisabled: true })) {
        reject(`${spec.placement} must be hidden after Remove Ads is active`);
        routeIsValid = false;
      }
    }

    if (spec.component === 'AdBanner') {
      const webAdBannerSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/AdBanner.tsx'),
        'utf8',
      );
      const nativeAdBannerSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/AdBanner.native.tsx'),
        'utf8',
      );

      if (
        !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*WEB_AD_FALLBACK_CONSENT_DECISION\s*,?\s*\)/.test(
          webAdBannerSource,
        )
      ) {
        reject('AdBanner web fallback must use the shared web fallback consent decision');
        routeIsValid = false;
      }
      if (!nativeAdBannerSource.includes('getPlatformAdUnitId(placement, Platform.OS)')) {
        reject('AdBanner native placement must resolve banner units by Platform.OS');
        routeIsValid = false;
      }
      if (
        !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*mobileAdsConsent\.decision\.consentDecision\s*,\s*Platform\.OS\s*,?\s*\)/.test(
          nativeAdBannerSource,
        )
      ) {
        reject('AdBanner native placement must gate banners through platform-aware shouldShowAd');
        routeIsValid = false;
      }
    }

    if (spec.component === 'NativeAdCard') {
      const consentAwareShouldShowPattern = new RegExp(
        `shouldShowAd\\(\\s*'${spec.placement}'\\s*,\\s*resolvedEntitlements\\s*,\\s*mobileAdsConsent\\.decision\\.consentDecision\\s*,\\s*Platform\\.OS\\s*,?\\s*\\)`,
      );
      const webFallbackShouldShowPattern = new RegExp(
        `shouldShowAd\\(\\s*'${spec.placement}'\\s*,\\s*resolvedEntitlements\\s*,\\s*WEB_AD_FALLBACK_CONSENT_DECISION\\s*,?\\s*\\)`,
      );
      const adsSource = fs.readFileSync(path.join(repoRoot, 'lib/monetization/ads.ts'), 'utf8');
      const adBannerSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/AdBanner.tsx'),
        'utf8',
      );
      const nativeAdCardSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/NativeAdCard.tsx'),
        'utf8',
      );
      const nativeAdCardNativeSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/NativeAdCard.native.tsx'),
        'utf8',
      );
      const nativeAdCopySource = fs.readFileSync(
        path.join(repoRoot, 'lib/monetization/adCopy.ts'),
        'utf8',
      );
      if (!adsSource.includes('export const WEB_AD_FALLBACK_CONSENT_DECISION')) {
        reject('ads.ts must export the shared web fallback consent decision');
        routeIsValid = false;
      }
      if (!adBannerSource.includes('WEB_AD_FALLBACK_CONSENT_DECISION')) {
        reject('AdBanner web fallback must use the shared web fallback consent decision');
        routeIsValid = false;
      }
      if (!webFallbackShouldShowPattern.test(nativeAdCardSource)) {
        reject(`NativeAdCard must gate ${spec.placement} through shouldShowAd`);
        routeIsValid = false;
      }
      if (!nativeAdCardSource.includes('WEB_AD_FALLBACK_CONSENT_DECISION')) {
        reject('NativeAdCard web fallback must use the shared web fallback consent decision');
        routeIsValid = false;
      }
      if (nativeAdCardSource.includes('react-native-google-mobile-ads')) {
        reject('NativeAdCard web fallback must not import native-only ad SDK APIs');
        routeIsValid = false;
      }
      if (
        !nativeAdCardSource.includes("const resultsNativeUnit = getAdUnit('results_native');") ||
        !nativeAdCardSource.includes(
          'getNativeAdCardCopy(language, { testOnly: resultsNativeUnit?.testOnly })',
        )
      ) {
        reject('NativeAdCard web fallback must choose live/test copy from the configured unit');
        routeIsValid = false;
      }
      if (!nativeAdCardNativeSource.includes('NativeAd.createForAdRequest')) {
        reject('NativeAdCard native placement must load results_native through NativeAd');
        routeIsValid = false;
      }
      if (!nativeAdCardNativeSource.includes('NativeAdView')) {
        reject('NativeAdCard native placement must render NativeAdView');
        routeIsValid = false;
      }
      if (!nativeAdCardNativeSource.includes('NativeAsset')) {
        reject('NativeAdCard native placement must register visible native ad assets');
        routeIsValid = false;
      }
      if (!nativeAdCardNativeSource.includes('NativeMediaView')) {
        reject('NativeAdCard native placement must render NativeMediaView');
        routeIsValid = false;
      }
      if (
        !nativeAdCardNativeSource.includes(`getPlatformAdUnitId('${spec.placement}', Platform.OS)`)
      ) {
        reject(`NativeAdCard native placement must resolve the ${spec.placement} unit by platform`);
        routeIsValid = false;
      }
      if (!consentAwareShouldShowPattern.test(nativeAdCardNativeSource)) {
        reject(
          `NativeAdCard native placement must gate ${spec.placement} through consent-aware shouldShowAd`,
        );
        routeIsValid = false;
      }
      if (!nativeAdCardNativeSource.includes('requestNonPersonalizedAdsOnly')) {
        reject('NativeAdCard native placement must pass non-personalized ad request options');
        routeIsValid = false;
      }
      if (!/\.destroy\(\)/.test(nativeAdCardNativeSource)) {
        reject('NativeAdCard native placement must destroy loaded native ads on cleanup');
        routeIsValid = false;
      }
      if (
        !nativeAdCardNativeSource.includes(
          "const resultsNativeUnit = getAdUnit('results_native');",
        ) ||
        !nativeAdCardNativeSource.includes(
          'getNativeAdCardCopy(language, { testOnly: resultsNativeUnit?.testOnly })',
        )
      ) {
        reject('NativeAdCard native placement must choose live/test copy from the configured unit');
        routeIsValid = false;
      }
      if (!nativeAdCopySource.includes('getNativeAdCardCopy')) {
        reject('NativeAdCard copy must expose a live/test selector');
        routeIsValid = false;
      }
      if (!/live:\s*\{[\s\S]*?accessibilityLabel:\s*'Ad:/.test(nativeAdCopySource)) {
        reject('NativeAdCard English live copy must identify the placement as an ad');
        routeIsValid = false;
      }
      if (!/live:\s*\{[\s\S]*?accessibilityLabel:\s*'Annons:/.test(nativeAdCopySource)) {
        reject('NativeAdCard Swedish live copy must identify the placement as an ad');
        routeIsValid = false;
      }
      if (!/test:\s*\{[\s\S]*?accessibilityLabel:\s*'Test native ad:/.test(nativeAdCopySource)) {
        reject('NativeAdCard test copy must keep explicit test-ad disclosure');
        routeIsValid = false;
      }
      const liveNativeAdCopyBlocks = Array.from(
        nativeAdCopySource.matchAll(/live:\s*\{([\s\S]*?)\n    \},\n    test:/g),
        (match) => match[1],
      );
      if (
        liveNativeAdCopyBlocks.length < 2 ||
        liveNativeAdCopyBlocks.some((block) =>
          /Test native ad|Inbyggd testannons|AdMob test placement preview|AdMob-testplacering/.test(
            block,
          ),
        )
      ) {
        reject('NativeAdCard live copy must not announce test-ad wording');
        routeIsValid = false;
      }
    }

    if (spec.component === 'AdBanner') {
      const webAdBannerSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/AdBanner.tsx'),
        'utf8',
      );
      const nativeAdBannerSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/AdBanner.native.tsx'),
        'utf8',
      );
      if (!nativeAdBannerSource.includes('getPlatformAdUnitId(placement, Platform.OS)')) {
        reject('AdBanner native placement must resolve banner units by Platform.OS');
        routeIsValid = false;
      }
      if (
        !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*mobileAdsConsent\.decision\.consentDecision\s*,\s*Platform\.OS\s*,?\s*\)/.test(
          nativeAdBannerSource,
        )
      ) {
        reject('AdBanner native placement must gate banners through platform-aware shouldShowAd');
        routeIsValid = false;
      }
      if (
        !/shouldShowAd\(\s*placement\s*,\s*resolvedEntitlements\s*,\s*WEB_AD_FALLBACK_CONSENT_DECISION\s*,?\s*\)/.test(
          webAdBannerSource,
        )
      ) {
        reject('AdBanner web fallback must use the shared web fallback consent decision');
        routeIsValid = false;
      }
      if (
        !/requestOptions=\{\{\s*requestNonPersonalizedAdsOnly:\s*mobileAdsConsent\.decision\.requestNonPersonalizedAdsOnly,\s*\}\}/.test(
          nativeAdBannerSource,
        )
      ) {
        reject(
          'AdBanner native placement must pass consent-derived non-personalized request options',
        );
        routeIsValid = false;
      }
      if (!nativeAdBannerSource.includes('size={BannerAdSize.ANCHORED_ADAPTIVE_BANNER}')) {
        reject('AdBanner native placement must render adaptive banner size');
        routeIsValid = false;
      }
    }

    if (spec.component === 'PracticeInterstitialAd') {
      const consentAwareShouldShowPattern = new RegExp(
        `shouldShowAd\\(\\s*'${spec.placement}'\\s*,\\s*resolvedEntitlements\\s*,\\s*mobileAdsConsent\\.decision\\.consentDecision\\s*,\\s*Platform\\.OS\\s*,?\\s*\\)`,
      );
      const webInterstitialSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/PracticeInterstitialAd.tsx'),
        'utf8',
      );
      const nativeInterstitialSource = fs.readFileSync(
        path.join(repoRoot, 'components/monetization/PracticeInterstitialAd.native.tsx'),
        'utf8',
      );

      if (/showKey=\{[\s\S]{0,160}selectedOptionId/.test(source)) {
        reject(
          'Practice route must key quiz_completed_interstitial by question and shuffle session, not selectedOptionId',
        );
        routeIsValid = false;
      }
      if (!source.includes('getPracticeInterstitialShowKey(question.id, shuffleSessionId)')) {
        reject('Practice route must use getPracticeInterstitialShowKey for interstitial capping');
        routeIsValid = false;
      }
      if (
        !webInterstitialSource.includes(`shouldShowAd('${spec.placement}', resolvedEntitlements)`)
      ) {
        reject(
          `PracticeInterstitialAd web fallback must gate ${spec.placement} through shouldShowAd`,
        );
        routeIsValid = false;
      }
      if (webInterstitialSource.includes('react-native-google-mobile-ads')) {
        reject('PracticeInterstitialAd web fallback must not import native-only ad SDK APIs');
        routeIsValid = false;
      }
      if (!webInterstitialSource.includes('getAdBannerStatusLabel')) {
        reject('PracticeInterstitialAd web fallback must use the shared live/test status selector');
        routeIsValid = false;
      }
      if (
        !webInterstitialSource.includes('const adStatusLabel = getAdBannerStatusLabel(copy, unit);')
      ) {
        reject('PracticeInterstitialAd web fallback must derive status copy from unit.testOnly');
        routeIsValid = false;
      }
      if (
        /unit\?\.testOnly\s*\?\s*copy\.testStatus\s*:\s*copy\.liveStatus/.test(
          webInterstitialSource,
        ) ||
        webInterstitialSource.includes('const adStatusLabel = copy.liveStatus')
      ) {
        reject('PracticeInterstitialAd web fallback must not inline live/test status copy');
        routeIsValid = false;
      }
      if (!nativeInterstitialSource.includes('InterstitialAd.createForAdRequest')) {
        reject('PracticeInterstitialAd native placement must load through InterstitialAd');
        routeIsValid = false;
      }
      if (
        !nativeInterstitialSource.includes(`getPlatformAdUnitId('${spec.placement}', Platform.OS)`)
      ) {
        reject(
          `PracticeInterstitialAd native placement must resolve the ${spec.placement} unit by platform`,
        );
        routeIsValid = false;
      }
      if (!consentAwareShouldShowPattern.test(nativeInterstitialSource)) {
        reject(
          `PracticeInterstitialAd native placement must gate ${spec.placement} through consent-aware platform shouldShowAd`,
        );
        routeIsValid = false;
      }
      if (!nativeInterstitialSource.includes('requestNonPersonalizedAdsOnly')) {
        reject(
          'PracticeInterstitialAd native placement must pass non-personalized ad request options',
        );
        routeIsValid = false;
      }
      if (
        !nativeInterstitialSource.includes('createPracticeInterstitialAttemptState') ||
        !nativeInterstitialSource.includes('reducePracticeInterstitialAttemptState')
      ) {
        reject('PracticeInterstitialAd native placement must use the shared attempt-state helper');
        routeIsValid = false;
      }
      if (
        !nativeInterstitialSource.includes('PRACTICE_INTERSTITIAL_LOAD_TIMEOUT_MS') ||
        !nativeInterstitialSource.includes('PRACTICE_INTERSTITIAL_SHOW_TIMEOUT_MS') ||
        !nativeInterstitialSource.includes("dispatchAttemptEvent('load_timeout')") ||
        !nativeInterstitialSource.includes("dispatchAttemptEvent('show_timeout')")
      ) {
        reject(
          'PracticeInterstitialAd native placement must release in-flight attempts on load and show timeouts',
        );
        routeIsValid = false;
      }
      if (/let attemptSettled|let showStarted/.test(nativeInterstitialSource)) {
        reject(
          'PracticeInterstitialAd native placement must not keep local attempt-settled bookkeeping outside the shared helper',
        );
        routeIsValid = false;
      }
      if (
        !nativeInterstitialSource.includes('AdEventType.OPENED') ||
        !nativeInterstitialSource.includes('AdEventType.CLOSED')
      ) {
        reject(
          'PracticeInterstitialAd native placement must consume the cap on opened/closed show paths',
        );
        routeIsValid = false;
      }
      if (
        /AdEventType\.LOADED[\s\S]{0,260}lastInterstitialShowKey\s*=/.test(nativeInterstitialSource)
      ) {
        reject('PracticeInterstitialAd must not consume the show key in the LOADED listener');
        routeIsValid = false;
      }
    }

    if (routeIsValid) adPlacementRoutesValidated += 1;
  }

  for (const file of EXPECTED_NO_AD_ROUTE_FILES) {
    let source = '';
    let routeIsValid = true;

    try {
      source = fs.readFileSync(path.join(repoRoot, file), 'utf8');
    } catch (error) {
      reject(`${file} could not be read for no-ad route parity: ${error.message}`);
      continue;
    }

    if (/AdBanner|NativeAd|Interstitial|LaunchPopupAd|RewardedAd/i.test(source)) {
      reject(`${file} must not import or render ad components`);
      routeIsValid = false;
    }

    if (
      /showRewardedExtraExamAd|rewardPreview|grantRewardedExamCredit|sponsor preview|Sponsored preview|Sponsrad förhandsvisning|Complete sponsor preview|Slutför förhandsvisning|Unlock extra exam|Lås upp extra prov/i.test(
        source,
      )
    ) {
      reject(`${file} must not expose rewarded ad unlock UI or sponsor-preview copy`);
      routeIsValid = false;
    }

    if (!blockedPlacements.includes('exam_screen')) {
      reject('adsConfig.blockedPlacements must include exam_screen');
      routeIsValid = false;
    }

    if (typeof shouldShowAd === 'function' && shouldShowAd('exam_screen', { adsDisabled: false })) {
      reject('exam_screen must never render ads');
      routeIsValid = false;
    }

    if (routeIsValid) noAdRoutesValidated += 1;
  }

  if (
    valid &&
    adPlacementRoutesValidated === EXPECTED_ROUTE_AD_PLACEMENTS.length &&
    noAdRoutesValidated === EXPECTED_NO_AD_ROUTE_FILES.length
  ) {
    adPlacementRouteParityValidated = true;
  }
}

function withProRuntimeScopeState({ env, e2e, e2eOverride } = {}, callback) {
  const previousEnv = process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE;
  const hadE2E = Object.prototype.hasOwnProperty.call(globalThis, '__SMT_E2E__');
  const hadE2EOverride = Object.prototype.hasOwnProperty.call(
    globalThis,
    '__SMT_ENABLE_PRO_RUNTIME_SCOPE__',
  );
  const previousE2E = globalThis.__SMT_E2E__;
  const previousE2EOverride = globalThis.__SMT_ENABLE_PRO_RUNTIME_SCOPE__;

  if (env === undefined) {
    delete process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE;
  } else {
    process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE = env;
  }

  if (e2e === undefined) {
    delete globalThis.__SMT_E2E__;
  } else {
    globalThis.__SMT_E2E__ = e2e;
  }

  if (e2eOverride === undefined) {
    delete globalThis.__SMT_ENABLE_PRO_RUNTIME_SCOPE__;
  } else {
    globalThis.__SMT_ENABLE_PRO_RUNTIME_SCOPE__ = e2eOverride;
  }

  try {
    return callback();
  } finally {
    if (previousEnv === undefined) {
      delete process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE;
    } else {
      process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE = previousEnv;
    }

    if (hadE2E) {
      globalThis.__SMT_E2E__ = previousE2E;
    } else {
      delete globalThis.__SMT_E2E__;
    }

    if (hadE2EOverride) {
      globalThis.__SMT_ENABLE_PRO_RUNTIME_SCOPE__ = previousE2EOverride;
    } else {
      delete globalThis.__SMT_ENABLE_PRO_RUNTIME_SCOPE__;
    }
  }
}

function validateReleaseMonetizationPolicyParity() {
  let valid = true;
  let releasePolicySource = '';
  let purchaseInflightSpecSource = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  if (!isObjectRecord(releaseMonetizationPolicy)) return;

  try {
    releasePolicySource = fs.readFileSync(
      path.join(repoRoot, 'lib/monetization/releasePolicy.ts'),
      'utf8',
    );
  } catch (error) {
    reject(`release monetization policy source could not be read: ${error.message}`);
    return;
  }

  try {
    purchaseInflightSpecSource = fs.readFileSync(
      path.join(repoRoot, 'tests/e2e/purchase-inflight-guard.spec.ts'),
      'utf8',
    );
  } catch (error) {
    reject(`purchase in-flight E2E spec source could not be read: ${error.message}`);
    return;
  }

  const expectedFieldValues = {
    adSupportedByDefault: true,
    adMobAppRecordRequired: true,
    appAdsTxtReviewRequired: true,
    consentPromptsRequired: EXPECTED_RELEASE_CONSENT_PROMPTS,
    noAdPlacements: EXPECTED_RELEASE_NO_AD_PLACEMENTS,
    privacyReviewRequiresBinary: true,
    proRuntimeScopeDefaultEnabled: false,
    proRuntimeScopeEnvFlag: 'EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE',
    proRuntimeScopeOverrideGate: 'release-scope-v11',
    realAdsEnvFlag: EXPECTED_RELEASE_REAL_ADS_ENV_FLAG,
    removeAdsPriceLabel: REMOVE_ADS_PRICE_LABEL,
    removeAdsProductId: REMOVE_ADS_PRODUCT_ID,
    removeAdsStoreProductIds: REMOVE_ADS_STORE_PRODUCT_IDS,
    storeDisclosureTopics: EXPECTED_RELEASE_STORE_DISCLOSURE_TOPICS,
  };

  const actualFieldNames = Object.keys(releaseMonetizationPolicy);
  if (!arrayEquals(actualFieldNames, EXPECTED_RELEASE_MONETIZATION_POLICY_FIELDS)) {
    reject(
      `releaseMonetizationPolicy fields are ${JSON.stringify(
        actualFieldNames,
      )}, expected ${JSON.stringify(EXPECTED_RELEASE_MONETIZATION_POLICY_FIELDS)}`,
    );
  }

  EXPECTED_RELEASE_MONETIZATION_POLICY_FIELDS.forEach((fieldName) => {
    const actualValue = releaseMonetizationPolicy[fieldName];
    const expectedValue = expectedFieldValues[fieldName];

    if (!jsonEqual(actualValue, expectedValue)) {
      reject(
        `releaseMonetizationPolicy.${fieldName} is ${JSON.stringify(
          actualValue,
        )}, expected ${JSON.stringify(expectedValue)}`,
      );
      return;
    }

    releaseMonetizationPolicyFieldsValidated += 1;
  });

  if (typeof isReleaseMonetizationPolicyReady !== 'function') return;
  if (!isReleaseMonetizationPolicyReady()) {
    reject('isReleaseMonetizationPolicyReady must return true for the current release policy');
  }

  if (typeof isProRuntimeScopeEnabled !== 'function') {
    reject('isProRuntimeScopeEnabled must be exported by the release monetization policy');
  } else {
    const proRuntimeScopeCases = [
      [
        withProRuntimeScopeState({}, () => isProRuntimeScopeEnabled()),
        false,
        'Pro runtime scope must default to false for v1.0 release builds',
      ],
      [
        withProRuntimeScopeState({ e2eOverride: true }, () => isProRuntimeScopeEnabled()),
        false,
        'Pro runtime E2E override must require __SMT_E2E__',
      ],
      [
        withProRuntimeScopeState({ e2e: true, e2eOverride: true }, () =>
          isProRuntimeScopeEnabled(),
        ),
        true,
        'Pro runtime E2E override must work when __SMT_E2E__ is true',
      ],
      [
        withProRuntimeScopeState({ env: 'true' }, () => isProRuntimeScopeEnabled()),
        true,
        'EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE=true must enable Pro runtime scope',
      ],
      [
        withProRuntimeScopeState({ env: 'false' }, () => isProRuntimeScopeEnabled()),
        false,
        'EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE=false must keep Pro runtime scope disabled',
      ],
    ];

    proRuntimeScopeCases.forEach(([actual, expected, message]) => {
      if (actual !== expected) reject(message);
    });
  }

  if (
    !/if\s*\(\s*runtime\.__SMT_E2E__\s*&&\s*runtime\.__SMT_ENABLE_PRO_RUNTIME_SCOPE__\s*===\s*true\s*\)/.test(
      releasePolicySource,
    )
  ) {
    reject('Pro runtime E2E override must require __SMT_E2E__');
  }

  if (!releasePolicySource.includes('process.env.EXPO_PUBLIC_ENABLE_PRO_RUNTIME_SCOPE')) {
    reject('Pro runtime scope must preserve the production env flag path');
  }

  if (
    !purchaseInflightSpecSource.includes('__SMT_E2E__: true') ||
    !purchaseInflightSpecSource.includes('__SMT_ENABLE_PRO_RUNTIME_SCOPE__: true')
  ) {
    reject('purchase-inflight E2E spec must seed __SMT_E2E__ with the Pro runtime override');
  }

  if (!Array.isArray(consentConfig?.prompts)) {
    reject('consentConfig.prompts must be an array for release policy parity');
  } else if (
    !arrayEquals(releaseMonetizationPolicy.consentPromptsRequired, consentConfig.prompts)
  ) {
    reject('releaseMonetizationPolicy consent prompts must match consentConfig.prompts');
  }

  if (!Array.isArray(adsConfig?.blockedPlacements)) {
    reject('adsConfig.blockedPlacements must be an array for release policy parity');
  } else if (!arrayEquals(releaseMonetizationPolicy.noAdPlacements, adsConfig.blockedPlacements)) {
    reject('releaseMonetizationPolicy no-ad placements must match adsConfig.blockedPlacements');
  }

  const storeDisclosureLabels = Array.isArray(consentConfig?.storeDisclosureLabels)
    ? consentConfig.storeDisclosureLabels
    : [];
  storeDisclosureLabels.forEach((label) => {
    if (!releaseMonetizationPolicy.storeDisclosureTopics?.includes(label)) {
      reject(`releaseMonetizationPolicy store disclosures must include ${label}`);
    }
  });

  if (
    valid &&
    releaseMonetizationPolicyFieldsValidated === EXPECTED_RELEASE_MONETIZATION_POLICY_FIELDS.length
  ) {
    releaseMonetizationPolicyParityValidated = true;
  }
}

function validateRemoveAdsEntitlementHookParity() {
  let valid = true;
  let hookSource = '';
  let homeSource = '';
  let premiumBannerSource = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    hookSource = fs.readFileSync(
      path.join(repoRoot, 'lib/monetization/useRemoveAdsEntitlements.ts'),
      'utf8',
    );
    homeSource = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/home.tsx'), 'utf8');
    premiumBannerSource = fs.readFileSync(
      path.join(repoRoot, 'components/monetization/PremiumBanner.tsx'),
      'utf8',
    );
  } catch (error) {
    reject(`Remove Ads entitlement sources could not be read: ${error.message}`);
    return;
  }

  const normalizedHookSource = hookSource.replace(/\s+/g, ' ');
  const normalizedHomeSource = homeSource.replace(/\s+/g, ' ');
  const normalizedPremiumBannerSource = premiumBannerSource.replace(/\s+/g, ' ');
  const resolvedAdEntitlementsHookStart = hookSource.indexOf(
    'export function useResolvedAdEntitlements',
  );
  const resolvedAdEntitlementsHookSource =
    resolvedAdEntitlementsHookStart === -1 ? '' : hookSource.slice(resolvedAdEntitlementsHookStart);
  const hookCases = [
    [
      /const\s+AD_BLOCKED_PENDING_ENTITLEMENTS:\s*PremiumEntitlements\s*=\s*\{[\s\S]*\.\.\.FREE_ENTITLEMENTS,[\s\S]*adsDisabled:\s*true,[\s\S]*\};/.test(
        hookSource,
      ),
      'Remove Ads entitlement hook must fail closed while purchase state loads',
    ],
    [
      /if\s*\(\s*!runtime\.__SMT_E2E__\s*\|\|\s*typeof runtime\.__SMT_REMOVE_ADS_MOCK_OWNED__ !== 'boolean'\s*\)\s*\{[\s\S]*return undefined;[\s\S]*\}/.test(
        hookSource,
      ),
      'E2E-owned web Remove Ads mock provider must require __SMT_E2E__',
    ],
    [
      /provider:\s*createMockPurchaseProvider\(\{\s*owned:\s*runtime\.__SMT_REMOVE_ADS_MOCK_OWNED__\s*\}\)/.test(
        hookSource,
      ),
      'E2E-owned web Remove Ads mock provider must honor __SMT_REMOVE_ADS_MOCK_OWNED__',
    ],
    [
      /function\s+createUnavailableWebPurchaseProvider\(\):\s*RemoveAdsPurchaseProvider\s*\{/.test(
        hookSource,
      ) &&
        /defaultWebPurchaseRuntimeOptions\s*\?\?=\s*\{[\s\S]*provider:\s*createUnavailableWebPurchaseProvider\(\),[\s\S]*purchaseUnavailableReason:\s*'web_store_unavailable',[\s\S]*storage:\s*createWebPurchaseStorage\(false\),[\s\S]*\};/.test(
          hookSource,
        ),
      'default web purchase runtime must fail closed without a public mock provider',
    ],
    [
      normalizedHookSource.includes('provider: createNativePurchaseProvider({') &&
        normalizedHookSource.includes('platform: nativePlatform,') &&
        normalizedHookSource.includes('receiptValidator,') &&
        normalizedHookSource.includes(
          "purchaseUnavailableReason: receiptValidator ? undefined : 'native_receipt_validator_unavailable',",
        ) &&
        normalizedHookSource.includes('storage: createSecureStorePurchaseStorage(),'),
      'native Remove Ads entitlement runtime must provide a native provider and secure storage',
    ],
    [
      /defaultNativePurchaseRuntimeOptions\s*\?\?=\s*\{[\s\S]*provider:\s*createNativePurchaseProvider\(\{[\s\S]*platform:\s*nativePlatform,[\s\S]*receiptValidator,[\s\S]*\}\),[\s\S]*purchaseUnavailableReason:[\s\S]*native_receipt_validator_unavailable[\s\S]*storage:\s*createSecureStorePurchaseStorage\(\),[\s\S]*\};/.test(
        hookSource,
      ),
      'native Remove Ads entitlement runtime must provide a native provider and secure storage',
    ],
    [
      /if\s*\(\s*!runtime\.__SMT_E2E__\s*\|\|\s*typeof\s+runtime\.__SMT_REMOVE_ADS_MOCK_OWNED__\s*!==\s*'boolean'\s*\)\s*\{[\s\S]*return\s+undefined;[\s\S]*\}/.test(
        hookSource,
      ),
      'E2E-owned web Remove Ads mock provider must require __SMT_E2E__',
    ],
    [
      /provider:\s*createMockPurchaseProvider\(\{\s*owned:\s*runtime\.__SMT_REMOVE_ADS_MOCK_OWNED__\s*\}\),/.test(
        hookSource,
      ),
      'E2E-owned web Remove Ads mock provider must honor __SMT_REMOVE_ADS_MOCK_OWNED__',
    ],
    [
      normalizedHookSource.includes('void getPurchaseEntitlements(purchaseRuntime)') &&
        normalizedHookSource.includes('publishRemoveAdsEntitlements(storedEntitlements);'),
      'Remove Ads entitlement hook must publish persisted purchase entitlements',
    ],
    [
      /\.catch\s*\(\s*\(\s*\)\s*=>\s*\{[\s\S]*setCurrentEntitlements\(AD_BLOCKED_PENDING_ENTITLEMENTS\);[\s\S]*setEntitlementsReady\(false\);[\s\S]*setEntitlementStatus\('read_failed'\);[\s\S]*\}\s*\)/.test(
        hookSource,
      ),
      'failed Remove Ads entitlement reads must stay ad-blocked and expose read_failed state',
    ],
    [
      /if\s*\(\s*hasExplicitEntitlements\s*\)\s*\{\s*return\s*\{[\s\S]*entitlements:\s*normalizedExplicitEntitlements\s*\?\?\s*FREE_ENTITLEMENTS,[\s\S]*entitlementsReady:\s*true,[\s\S]*entitlementStatus:\s*'ready'\s+as\s+const,?[\s\S]*\};\s*\}/.test(
        hookSource,
      ) && /adsDisabled:\s*explicitEntitlements\.adsDisabled\s*===\s*true/.test(hookSource),
      'explicit ad entitlements must bypass async purchase loading as ready',
    ],
    [
      /skipPurchaseRuntime\s*=\s*false/.test(hookSource) &&
        /function\s+useRemoveAdsEntitlementsRuntime\(/.test(hookSource) &&
        /purchaseRuntimeEnabled\s*\?\s*\(?runtimeOptions\s*\?\?\s*createDefaultPurchaseRuntimeOptions\(initialEntitlements\.adsDisabled\s*===\s*true\)\)?\s*:\s*undefined/.test(
          hookSource,
        ) &&
        /if\s*\(\s*!purchaseRuntimeEnabled\s*\|\|\s*!purchaseRuntime\s*\)\s*\{[\s\S]*applyEntitlements\(initialEntitlements\);[\s\S]*return\s*\(\)\s*=>\s*\{[\s\S]*isMounted\s*=\s*false;[\s\S]*\};[\s\S]*\}/.test(
          hookSource,
        ) &&
        /purchaseRuntimeEnabled:\s*!skipPurchaseRuntime/.test(hookSource) &&
        /const\s+hasExplicitEntitlements\s*=\s*explicitEntitlements\s*!==\s*undefined;/.test(
          hookSource,
        ) &&
        /useRemoveAdsEntitlementsRuntime\(\{[\s\S]*purchaseRuntimeEnabled:\s*!hasExplicitEntitlements/.test(
          resolvedAdEntitlementsHookSource,
        ) &&
        !/useRemoveAdsEntitlements\(\{/.test(resolvedAdEntitlementsHookSource) &&
        !/skipPurchaseRuntime/.test(resolvedAdEntitlementsHookSource),
      'explicit ad entitlements must skip purchase runtime creation and storage reads',
    ],
    [
      /if\s*\(\s*!entitlementsReady\s*\)\s*\{\s*return\s*\{[\s\S]*entitlements:\s*AD_BLOCKED_PENDING_ENTITLEMENTS,[\s\S]*entitlementsReady:\s*false,[\s\S]*entitlementStatus,?[\s\S]*\};\s*\}/.test(
        hookSource,
      ),
      'unresolved purchase state must return ad-blocked pending entitlements',
    ],
    [
      /\bentitlementsReady\b/.test(homeSource) &&
        normalizedHomeSource.includes(
          'const showRemoveAdsOffer = entitlementsReady && monetizationEntitlements.adsDisabled !== true;',
        ) &&
        /\{showRemoveAdsOffer\s*\?\s*\([\s\S]{0,420}<PricingWedge/.test(homeSource) &&
        /\{entitlementsReady\s*\?\s*\([\s\S]{0,1200}<PremiumBanner[\s\S]{0,1200}<AdBanner\s+entitlements=\{monetizationEntitlements\}\s+placement="home_banner"\s*\/>/.test(
          homeSource,
        ),
      'Home monetization surfaces must wait for Remove Ads entitlements before rendering',
    ],
    [
      normalizedPremiumBannerSource.includes(
        "purchaseRuntime?.purchaseUnavailableReason === 'web_store_unavailable'",
      ) &&
        normalizedPremiumBannerSource.includes('copy.webUnavailableBody(resolvedPriceLabel)') &&
        normalizedPremiumBannerSource.includes('copy.body(resolvedPriceLabel)') &&
        normalizedPremiumBannerSource.includes('copy.webUnavailableAccessibilityHint') &&
        normalizedPremiumBannerSource.includes('copy.buyUnavailable') &&
        normalizedPremiumBannerSource.includes('copy.restoreUnavailable') &&
        /Buy in mobile app/.test(premiumBannerSource) &&
        /Köp i mobilappen/.test(premiumBannerSource) &&
        /web version shows status only/.test(premiumBannerSource) &&
        /Webbversionen visar bara status/.test(premiumBannerSource),
      'PremiumBanner must render localized mobile-app-only copy when web purchases are unavailable',
    ],
  ];

  hookCases.forEach(([caseIsValid, message]) => {
    if (!caseIsValid) {
      reject(message);
      return;
    }
    removeAdsEntitlementHookCasesValidated += 1;
  });

  if (valid && removeAdsEntitlementHookCasesValidated === EXPECTED_REMOVE_ADS_HOOK_CASES) {
    removeAdsEntitlementHookParityValidated = true;
  }
}

function validatePremiumEntitlementParity() {
  let valid = true;
  let premiumSource = '';
  let adsSource = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    premiumSource = fs.readFileSync(path.join(repoRoot, 'lib/monetization/premium.ts'), 'utf8');
  } catch (error) {
    reject(`lib/monetization/premium.ts could not be read: ${error.message}`);
  }

  try {
    adsSource = fs.readFileSync(path.join(repoRoot, 'lib/monetization/ads.ts'), 'utf8');
  } catch (error) {
    reject(`lib/monetization/ads.ts could not be read: ${error.message}`);
  }

  const entitlementExports = {
    FREE_ENTITLEMENTS,
    PREMIUM_ENTITLEMENTS,
    REMOVE_ADS_ENTITLEMENTS,
  };
  const entitlementFields = ['adsDisabled', 'unlimitedMockExams', 'fullMistakeReview'];

  EXPECTED_PREMIUM_ENTITLEMENT_STATES.forEach(({ configKey, entitlements, exportName }) => {
    const actualEntitlements = entitlementExports[exportName];
    let stateIsValid = true;

    function rejectState(message) {
      stateIsValid = false;
      reject(message);
    }

    if (!isObjectRecord(actualEntitlements)) {
      rejectState(`${exportName} must be an object`);
    } else {
      const actualFields = Object.keys(actualEntitlements);
      if (!arrayEquals(actualFields, entitlementFields)) {
        rejectState(
          `${exportName} fields are ${JSON.stringify(actualFields)}, expected ${JSON.stringify(
            entitlementFields,
          )}`,
        );
      }

      entitlementFields.forEach((fieldName) => {
        if (typeof actualEntitlements[fieldName] !== 'boolean') {
          rejectState(`${exportName}.${fieldName} must be boolean`);
        } else if (actualEntitlements[fieldName] !== entitlements[fieldName]) {
          rejectState(
            `${exportName}.${fieldName} is ${actualEntitlements[fieldName]}, expected ${entitlements[fieldName]}`,
          );
        }
      });
    }

    if (!isObjectRecord(premiumConfig?.[configKey])) {
      rejectState(`premiumConfig.${configKey} must expose ${exportName}`);
    } else if (!jsonEqual(premiumConfig[configKey], actualEntitlements)) {
      rejectState(`premiumConfig.${configKey} must match ${exportName}`);
    }

    if (stateIsValid) premiumEntitlementStatesValidated += 1;
  });

  if (typeof hasAdsDisabled === 'function') {
    if (hasAdsDisabled(FREE_ENTITLEMENTS) !== false) {
      reject('hasAdsDisabled must return false for FREE_ENTITLEMENTS');
    }
    if (hasAdsDisabled(REMOVE_ADS_ENTITLEMENTS) !== true) {
      reject('hasAdsDisabled must return true for REMOVE_ADS_ENTITLEMENTS');
    }
    if (hasAdsDisabled({ adsDisabled: 'yes' }) !== false) {
      reject('hasAdsDisabled must require adsDisabled === true');
    }
  }

  if (typeof isPremiumUser === 'function') {
    if (isPremiumUser(FREE_ENTITLEMENTS) !== false) {
      reject('isPremiumUser must return false for FREE_ENTITLEMENTS');
    }
    if (isPremiumUser(PREMIUM_ENTITLEMENTS) !== true) {
      reject('isPremiumUser must return true for PREMIUM_ENTITLEMENTS');
    }
    if (isPremiumUser(REMOVE_ADS_ENTITLEMENTS) !== false) {
      reject('isPremiumUser must not treat Remove Ads as full premium');
    }
    if (
      isPremiumUser({
        adsDisabled: false,
        unlimitedMockExams: true,
        fullMistakeReview: true,
      }) !== true
    ) {
      reject('isPremiumUser must stay decoupled from adsDisabled');
    }
    if (
      isPremiumUser({
        adsDisabled: false,
        unlimitedMockExams: true,
        fullMistakeReview: 1,
      }) !== false
    ) {
      reject('isPremiumUser must require strict boolean premium flags');
    }
  }

  if (typeof shouldShowAd === 'function' && shouldShowAd('home_banner', REMOVE_ADS_ENTITLEMENTS)) {
    reject('shouldShowAd must not render home_banner when adsDisabled is true');
  }

  if (
    !/if\s*\(\s*isStrictEntitlementFlag\(entitlements\.adsDisabled\)\s*\)\s*return false;/.test(
      adsSource,
    )
  ) {
    reject('shouldShowAd must keep an explicit adsDisabled fail-closed branch');
  }

  if (
    !/return\s*\(\s*isStrictEntitlementFlag\(entitlements\.unlimitedMockExams\)\s*&&\s*isStrictEntitlementFlag\(entitlements\.fullMistakeReview\)\s*\);/.test(
      premiumSource,
    )
  ) {
    reject('isPremiumUser must depend on strict premium capabilities rather than adsDisabled');
  }

  if (valid && premiumEntitlementStatesValidated === EXPECTED_PREMIUM_ENTITLEMENT_STATES.length) {
    premiumEntitlementParityValidated = true;
  }
}

function validateQuestionDisclaimerParity() {
  let copyIsValid = true;

  function rejectCopy(message) {
    copyIsValid = false;
    fail(message);
  }

  let componentSource = '';
  let disclaimerRouteSource = '';
  try {
    componentSource = fs.readFileSync(
      path.join(repoRoot, 'components/quiz/QuestionDisclaimer.tsx'),
      'utf8',
    );
  } catch (error) {
    rejectCopy(`components/quiz/QuestionDisclaimer.tsx could not be read: ${error.message}`);
  }
  try {
    disclaimerRouteSource = fs.readFileSync(path.join(repoRoot, 'app/disclaimer.tsx'), 'utf8');
  } catch (error) {
    rejectCopy(`app/disclaimer.tsx could not be read: ${error.message}`);
  }

  const componentLower = componentSource.toLocaleLowerCase('en-US');
  const routeLower = disclaimerRouteSource.toLocaleLowerCase('en-US');
  REQUIRED_QUESTION_DISCLAIMER_PHRASES.forEach((phrase) => {
    const normalizedPhrase = phrase.toLocaleLowerCase('en-US');
    if (!componentLower.includes(normalizedPhrase)) {
      rejectCopy(`QuestionDisclaimer missing required "${phrase}" wording`);
    }
    if (!routeLower.includes(normalizedPhrase)) {
      rejectCopy(`app/disclaimer.tsx missing required "${phrase}" wording`);
    }
  });

  if (!/export function QuestionDisclaimer/.test(componentSource)) {
    rejectCopy('QuestionDisclaimer component must keep its named export');
  }
  if (/guaranteed|guarantee/i.test(componentSource)) {
    rejectCopy('QuestionDisclaimer must not imply guaranteed exam outcomes');
  }

  if (copyIsValid) questionDisclaimerCopyValidated = true;

  EXPECTED_QUESTION_DISCLAIMER_ROUTES.forEach(({ route, file }) => {
    let routeIsValid = true;
    let source = '';

    try {
      source = fs.readFileSync(path.join(repoRoot, file), 'utf8');
    } catch (error) {
      routeIsValid = false;
      fail(`${file} could not be read for ${route} disclaimer coverage: ${error.message}`);
    }

    if (!/import\s+\{\s*QuestionDisclaimer\s*\}/.test(source)) {
      routeIsValid = false;
      fail(`${file} must import QuestionDisclaimer for ${route}`);
    }
    if (!QUESTION_DISCLAIMER_USAGE_PATTERN.test(source)) {
      routeIsValid = false;
      fail(`${file} is missing QuestionDisclaimer for ${route}`);
    }

    if (routeIsValid) questionDisclaimerRoutesValidated += 1;
  });
}

if (process.argv.includes('--focus-question-disclaimer-parity')) {
  validateQuestionDisclaimerParity();
  exitWithValidationFailures();
  printValidationSummary({
    questionDisclaimerRoutesValidated,
    questionDisclaimerCopyValidated,
  });
  process.exit(0);
}

function validateMockExamConfigTypeSchemaParity() {
  let valid = true;
  let mockExamConfigSource = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    mockExamConfigSource = fs.readFileSync(path.join(repoRoot, 'data/mockExamConfig.ts'), 'utf8');
  } catch (error) {
    reject(`data/mockExamConfig.ts could not be read: ${error.message}`);
    return;
  }

  const actualFields = extractObjectTypePropertiesFromTs(mockExamConfigSource, 'MockExamConfig');
  if (!Array.isArray(actualFields)) {
    reject('data/mockExamConfig.ts MockExamConfig interface could not be read');
    return;
  }

  const actualNames = actualFields.map((field) => field.name);
  const expectedNames = EXPECTED_MOCK_EXAM_CONFIG_FIELDS.map((field) => field.name);
  if (!arrayEquals(actualNames, expectedNames)) {
    reject(
      `MockExamConfig fields are ${JSON.stringify(actualNames)}, expected ${JSON.stringify(
        expectedNames,
      )}`,
    );
  }

  const actualFieldsByName = new Map(actualFields.map((field) => [field.name, field]));
  EXPECTED_MOCK_EXAM_CONFIG_FIELDS.forEach((expectedField) => {
    const actualField = actualFieldsByName.get(expectedField.name);
    let fieldIsValid = true;

    function rejectField(message) {
      fieldIsValid = false;
      reject(message);
    }

    if (!actualField) {
      rejectField(`MockExamConfig missing ${expectedField.name}`);
    } else {
      if (actualField.type !== expectedField.type) {
        rejectField(
          `MockExamConfig.${expectedField.name} type is ${actualField.type}, expected ${expectedField.type}`,
        );
      }
      if (actualField.optional !== expectedField.optional) {
        rejectField(
          `MockExamConfig.${expectedField.name} optional=${actualField.optional}, expected ${expectedField.optional}`,
        );
      }
    }

    if (fieldIsValid) mockExamConfigTypeFieldsValidated += 1;
  });

  if (valid && mockExamConfigTypeFieldsValidated === EXPECTED_MOCK_EXAM_CONFIG_FIELDS.length) {
    mockExamConfigTypeSchemaParityValidated = true;
  }
}

function validateMockExamConfig(config, publishedQuestionCount) {
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  if (!config || typeof config !== 'object') {
    reject('defaultMockExamConfig export is not an object');
  } else {
    mockExamConfigExactSchemaKeyFailures(config, 'defaultMockExamConfig').forEach(reject);

    if (!Number.isInteger(config.questionCount) || config.questionCount < 1) {
      reject('defaultMockExamConfig questionCount must be a positive integer');
    } else if (config.questionCount > publishedQuestionCount) {
      reject(
        `defaultMockExamConfig questionCount ${config.questionCount} exceeds ${publishedQuestionCount} published questions`,
      );
    }

    if (!Number.isInteger(config.durationMinutes) || config.durationMinutes < 1) {
      reject('defaultMockExamConfig durationMinutes must be a positive integer');
    }
    if (config.sourceScope !== 'uhr_based') {
      reject('defaultMockExamConfig sourceScope must be uhr_based');
    }
    if (config.showExplanationsDuringExam !== false) {
      reject('defaultMockExamConfig must not show explanations during the exam');
    }
    if (config.adsAllowedDuringExam !== false) {
      reject('defaultMockExamConfig must not allow ads during the exam');
    }
  }

  if (valid) {
    mockExamConfigExactSchemaKeysValidated = true;
    mockExamConfigValidated = true;
  }
}

function validateMockExamRuntimeParity(config) {
  if (!config || typeof config !== 'object' || !Array.isArray(questions)) return;
  if (typeof generateExam !== 'function') return;

  const examQuestions = generateExam(questions, { questionCount: config.questionCount });
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  if (!Array.isArray(examQuestions)) {
    reject('generateExam did not return an array for defaultMockExamConfig');
    return;
  }

  if (examQuestions.length !== config.questionCount) {
    reject(
      `default mock exam generated ${examQuestions.length} questions, expected ${config.questionCount}`,
    );
  }

  const examQuestionIds = new Set();
  const expectedChapterCoverage = Math.min(
    Array.isArray(chapters) ? chapters.length : 0,
    config.questionCount,
  );
  const coveredChapters = new Set();
  const chapterCounts = new Map();
  examQuestions.forEach((question, index) => {
    const label = question?.id || `mock exam question[${index}]`;

    if (!question || typeof question !== 'object') {
      reject(`mock exam question[${index}] is not an object`);
      return;
    }
    if (examQuestionIds.has(question.id)) {
      reject(`default mock exam repeats question ${question.id}`);
    }
    if (hasText(question.id)) examQuestionIds.add(question.id);
    if (question.reviewStatus !== 'published') {
      reject(`${label} mock exam reviewStatus is ${question.reviewStatus}, expected published`);
    }
    if (!question.uhrReference?.chapter || !question.uhrReference?.section) {
      reject(`${label} mock exam question is missing a UHR reference`);
    }
    if (hasText(question.chapterId)) {
      coveredChapters.add(question.chapterId);
      chapterCounts.set(question.chapterId, (chapterCounts.get(question.chapterId) || 0) + 1);
    }
  });

  if (expectedChapterCoverage > 0 && coveredChapters.size !== expectedChapterCoverage) {
    reject(
      `default mock exam covers ${coveredChapters.size} chapters, expected ${expectedChapterCoverage}`,
    );
  }

  const chapterCountValues = [...chapterCounts.values()];
  if (config.questionCount > 0 && chapterCountValues.length === 0) {
    reject('default mock exam did not count any chapter buckets');
  } else if (chapterCountValues.length > 0) {
    const minChapterCount = Math.min(...chapterCountValues);
    const maxChapterCount = Math.max(...chapterCountValues);
    const countedQuestions = chapterCountValues.reduce((sum, count) => sum + count, 0);

    if (countedQuestions !== examQuestions.length) {
      reject(
        `default mock exam counted ${countedQuestions} chapter assignments for ${examQuestions.length} questions`,
      );
    }
    if (maxChapterCount - minChapterCount > 1) {
      reject(
        `default mock exam chapter counts are unbalanced: ${JSON.stringify(Object.fromEntries(chapterCounts))}`,
      );
    }
  }

  if (valid) mockExamRuntimeParityValidated = true;
  if (valid) mockExamChapterBalanceParityValidated = true;
}

function validateMockExamChapterDistributionSafety() {
  if (typeof materializeMock !== 'function') return;

  let valid = true;
  let casesValidated = 0;

  function reject(message) {
    valid = false;
    fail(message);
  }

  function validateCase(condition, message) {
    casesValidated += 1;
    if (!condition) reject(message);
  }

  const materialized = materializeMock({
    mockId: 'mock-2',
    bank: [
      { id: 'distribution-valid-1', difficulty: 'medium', chapterId: 'ch01' },
      { id: 'distribution-valid-2', difficulty: 'medium', chapterId: ' ch02 ' },
      { id: 'distribution-valid-3', difficulty: 'medium', chapterId: 'ch02' },
      { id: 'distribution-proto', difficulty: 'medium', chapterId: '__proto__' },
      { id: 'distribution-constructor', difficulty: 'medium', chapterId: 'constructor' },
      { id: 'distribution-prototype', difficulty: 'medium', chapterId: 'prototype' },
      { id: 'distribution-blank', difficulty: 'medium', chapterId: '   ' },
      { id: 'distribution-number', difficulty: 'medium', chapterId: 17 },
      { id: 'distribution-object', difficulty: 'medium', chapterId: { id: 'ch03' } },
    ],
  });
  const distribution = materialized?.chapterDistribution;

  validateCase(
    distribution && typeof distribution === 'object',
    'mock exam library must return a chapterDistribution object',
  );
  if (!distribution || typeof distribution !== 'object') {
    mockExamChapterDistributionSafetyCasesValidated = casesValidated;
    return;
  }

  validateCase(
    Object.getPrototypeOf(distribution) === null,
    'mock exam chapterDistribution must use a null-prototype map',
  );
  validateCase(
    distribution.ch01 === 1,
    `mock exam chapterDistribution ch01 count is ${distribution.ch01}, expected 1`,
  );
  validateCase(
    distribution.ch02 === 2,
    `mock exam chapterDistribution ch02 count is ${distribution.ch02}, expected 2`,
  );

  for (const unsafeKey of ['__proto__', 'constructor', 'prototype']) {
    validateCase(
      !Object.prototype.hasOwnProperty.call(distribution, unsafeKey) &&
        distribution[unsafeKey] === undefined,
      `mock exam chapterDistribution must reject unsafe chapter id ${unsafeKey}`,
    );
  }

  const distributionKeys = Object.keys(distribution).sort();
  validateCase(
    JSON.stringify(distributionKeys) === JSON.stringify(['ch01', 'ch02']),
    `mock exam chapterDistribution keys are ${JSON.stringify(
      distributionKeys,
    )}, expected only ch01/ch02`,
  );
  validateCase(
    Object.values(distribution).every(
      (count) => Number.isInteger(count) && Number.isFinite(count) && count > 0,
    ),
    'mock exam chapterDistribution counts must be positive finite integers',
  );

  mockExamChapterDistributionSafetyCasesValidated = casesValidated;
  if (valid && casesValidated === 9) mockExamChapterDistributionSafetyParityValidated = true;
}

function expectedFormattedExamTime(totalSeconds) {
  const safeSeconds = Math.max(0, Math.floor(totalSeconds));
  const minutes = Math.floor(safeSeconds / 60);
  const seconds = safeSeconds % 60;
  return `${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
}

function validateMockExamTimerParity(config) {
  if (!config || typeof config !== 'object') return;
  if (
    typeof formatExamTime !== 'function' ||
    typeof getMockExamTimerUrgency !== 'function' ||
    typeof shouldAutoSubmitExam !== 'function'
  ) {
    return;
  }

  const totalSeconds = config.durationMinutes * 60;
  let valid = true;
  let examRoute = '';
  let statusBar = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    examRoute = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/exam.tsx'), 'utf8');
    statusBar = fs.readFileSync(path.join(repoRoot, 'components/MockExamStatusBar.tsx'), 'utf8');
  } catch (error) {
    reject(`mock exam timer source could not be read: ${error.message}`);
    return;
  }

  if (!Number.isInteger(totalSeconds) || totalSeconds < 60) {
    reject('defaultMockExamConfig duration must convert to at least 60 whole seconds');
  }

  const formattedStartTime = formatExamTime(totalSeconds);
  const expectedStartTime = expectedFormattedExamTime(totalSeconds);
  if (formattedStartTime !== expectedStartTime) {
    reject(
      `formatExamTime default duration is ${formattedStartTime}, expected ${expectedStartTime}`,
    );
  }

  const liveExamState = {
    examActive: true,
    remainingSeconds: totalSeconds,
    submitted: false,
    questionCount: config.questionCount,
  };
  if (shouldAutoSubmitExam(liveExamState)) {
    reject('shouldAutoSubmitExam must not submit at the configured start time');
  }
  if (
    !shouldAutoSubmitExam({
      ...liveExamState,
      remainingSeconds: 0,
    })
  ) {
    reject('shouldAutoSubmitExam must submit a live exam when the timer reaches zero');
  }
  if (
    shouldAutoSubmitExam({
      ...liveExamState,
      remainingSeconds: 0,
      submitted: true,
    })
  ) {
    reject('shouldAutoSubmitExam must not resubmit an already submitted exam');
  }
  if (
    shouldAutoSubmitExam({
      ...liveExamState,
      remainingSeconds: 0,
      questionCount: 0,
    })
  ) {
    reject('shouldAutoSubmitExam must not submit an empty exam');
  }
  if (formatExamTime(-1) !== '00:00') {
    reject('formatExamTime must clamp negative remaining time to 00:00');
  }
  const timerUrgencyCases = [
    {
      expected: 'steady',
      input: { remainingSeconds: totalSeconds, totalSeconds },
      label: 'start time',
    },
    {
      expected: 'steady',
      input: { remainingSeconds: Math.floor(totalSeconds * 0.5) + 1, totalSeconds },
      label: 'above half time',
    },
    {
      expected: 'warning',
      input: { remainingSeconds: Math.floor(totalSeconds * 0.5), totalSeconds },
      label: 'half time',
    },
    {
      expected: 'warning',
      input: { remainingSeconds: Math.ceil(totalSeconds * 0.25), totalSeconds },
      label: 'quarter time',
    },
    {
      expected: 'danger',
      input: { remainingSeconds: Math.ceil(totalSeconds * 0.25) - 1, totalSeconds },
      label: 'below quarter time',
    },
    {
      expected: 'danger',
      input: { remainingSeconds: Number.NaN, totalSeconds },
      label: 'malformed remaining time',
    },
  ];
  for (const { expected, input, label } of timerUrgencyCases) {
    const actual = getMockExamTimerUrgency(input);
    if (actual !== expected) {
      reject(`getMockExamTimerUrgency returned ${actual} for ${label}, expected ${expected}`);
      break;
    }
  }
  for (const malformedRemainingSeconds of [
    Number.NaN,
    Number.POSITIVE_INFINITY,
    '0',
    null,
    undefined,
  ]) {
    if (formatExamTime(malformedRemainingSeconds) !== '00:00') {
      reject('formatExamTime must render malformed remaining time as 00:00');
      break;
    }
  }
  const malformedAutoSubmitStates = [
    { ...liveExamState, examActive: undefined, remainingSeconds: 0 },
    { ...liveExamState, examActive: 'yes', remainingSeconds: 0 },
    { ...liveExamState, remainingSeconds: '0' },
    { ...liveExamState, remainingSeconds: Number.NaN },
    { ...liveExamState, submitted: 0, remainingSeconds: 0 },
    { ...liveExamState, questionCount: '1', remainingSeconds: 0 },
    { ...liveExamState, questionCount: null, remainingSeconds: 0 },
    { ...liveExamState, questionCount: Number.POSITIVE_INFINITY, remainingSeconds: 0 },
  ];
  for (const malformedState of malformedAutoSubmitStates) {
    if (shouldAutoSubmitExam(malformedState)) {
      reject('shouldAutoSubmitExam must ignore malformed runtime timer state');
      break;
    }
  }

  const routeSnippets = [
    [
      "import { MockExamStatusBar } from '../../components/MockExamStatusBar';",
      'active mock exam route must import the status bar',
    ],
    [
      'getMockExamTimerUrgency',
      'active mock exam route must derive timer urgency from the quiz helper',
    ],
    [
      'const totalExamSeconds = defaultMockExamConfig.durationMinutes * 60;',
      'active mock exam route must derive total timer seconds from mock exam config',
    ],
    [
      'const timerUrgency = getMockExamTimerUrgency({',
      'active mock exam route must derive urgency from remaining and total seconds',
    ],
    [
      'totalSeconds: totalExamSeconds',
      'active mock exam route urgency must use configured total seconds',
    ],
    ['<MockExamStatusBar', 'active mock exam route must render the status bar'],
    ['timerUrgency={timerUrgency}', 'status bar must receive computed timer urgency'],
    [
      'timeValue={formatExamTime(remainingSeconds)}',
      'status bar must keep the existing formatted timer text visible',
    ],
    [
      'submitDisabled={!canSubmit}',
      'status bar submit action must preserve all-answers-before-submit gating',
    ],
    [
      'const mockExamRealisticMode = useSettingsStore((state) => state.mockExamRealisticMode);',
      'mock exam route must read the realistic-mode setting',
    ],
    [
      'const shouldPause = canPause && !mockExamRealisticMode && awayFromExam;',
      'mock exam route must keep standard-mode pause separate from realistic mode',
    ],
    [
      "setExamPauseStatus('focusBreak');",
      'mock exam route must announce realistic-mode focus breaks',
    ],
    [
      'focusBreaks: focusBreaksRef.current',
      'mock exam route must persist focus-break count with the submitted result',
    ],
  ];
  for (const [snippet, message] of routeSnippets) {
    if (!examRoute.includes(snippet)) reject(message);
  }

  const statusBarSnippets = [
    ['type MockExamStatusBarCopy = {', 'status bar must keep typed localized copy'],
    ['timerUrgency: Record<MockExamTimerUrgency, string>;', 'status bar must type urgency copy'],
    ["steady: 'Gott om tid'", 'status bar must include Swedish steady timer copy'],
    ["warning: 'Tiden börjar ta slut'", 'status bar must include Swedish low-time timer copy'],
    ["danger: 'Kritiskt lite tid kvar'", 'status bar must include Swedish critical timer copy'],
    ["steady: 'Time steady'", 'status bar must include English steady timer copy'],
    ["warning: 'Time running low'", 'status bar must include English low-time timer copy'],
    ["danger: 'Critical time remaining'", 'status bar must include English critical timer copy'],
    [
      'const timerBadgeVariant: Record<MockExamTimerUrgency, PillBadgeVariant>',
      'status bar must map urgency states to non-hardcoded badge variants',
    ],
    ["danger: 'danger'", 'status bar danger timer state must use the danger badge variant'],
    [
      'style={[styles.bar, styles[`${resolvedTimerUrgency}TimeBar`], style]}',
      'status bar must expose urgency through tokenized styles',
    ],
    [
      'backgroundColor: colors.dangerSoft',
      'status bar danger timer state must use the semantic danger surface token',
    ],
    [
      'borderColor: colors.danger',
      'status bar danger timer state must use the semantic danger border token',
    ],
    [
      'accessibilityLabel={`${resolvedTimeLabel}: ${timeValue}. ${resolvedTimerUrgencyLabel}`}',
      'status bar timer badge must expose non-color urgency copy',
    ],
    ['{resolvedTimerUrgencyLabel}', 'status bar must render visible non-color timer urgency copy'],
  ];
  for (const [snippet, message] of statusBarSnippets) {
    if (!statusBar.includes(snippet)) reject(message);
  }

  if (valid) mockExamTimerParityValidated = true;
}

function validateExamSubmissionFinalityParity() {
  let valid = true;
  let examRoute = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    examRoute = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/exam.tsx'), 'utf8');
  } catch (error) {
    reject(`app/(tabs)/exam.tsx could not be read: ${error.message}`);
    return;
  }

  if (
    !examRoute.includes('Submitted results are final. Start another mock exam for a fresh attempt.')
  ) {
    reject('exam result screen must tell users submitted results are final');
  }
  if (examRoute.includes('Back to exam answers') || examRoute.includes('Back to answers')) {
    reject('exam result screen must not offer a back-to-answers control after submission');
  }
  if (examRoute.includes('onPress={() => setSubmitted(false)}')) {
    reject('exam result screen must not directly reopen submitted answers');
  }
  if (
    !examRoute.includes(
      'disabled: !completionRecorded || !canStartAccessibleExam || startingAccessibleExam',
    ) ||
    !examRoute.includes(
      'disabled={!completionRecorded || !canStartAccessibleExam || startingAccessibleExam}',
    )
  ) {
    reject('next-exam control must stay disabled until the submitted completion is stored');
  }
  if (
    !examRoute.includes('const recordMockExamSession = useProgressStore') ||
    !examRoute.includes('recordMockExamSession({')
  ) {
    reject('exam result submission must persist a completed mock-exam score for readiness');
  }
  const recordMockExamSessionCalls = examRoute.match(/\brecordMockExamSession\s*\(\s*\{/g) ?? [];
  if (recordMockExamSessionCalls.length !== 1) {
    reject('exam result submission must persist exactly one completed mock-exam session');
  }
  const requiredPersistenceFields = [
    'sessionId: examAttemptId',
    'score: resultTotalCount > 0 ? resultCorrectCount / resultTotalCount : 0',
    'completedAt: submittedExamSession?.completedAt ?? new Date().toISOString()',
    'correctCount: resultCorrectCount',
    'totalCount: resultTotalCount',
    'focusBreaks: focusBreaksRef.current',
    'questionTimings:',
    'submittedExamSession?.answers',
    'timeSpentSeconds: answer.timeSpentSeconds',
  ];
  for (const snippet of requiredPersistenceFields) {
    if (!examRoute.includes(snippet)) {
      reject(`exam result submission must persist readiness field: ${snippet}`);
    }
  }

  if (valid) examSubmissionFinalityParityValidated = true;
}

function countExamRouteHeaderOccurrences(source, { styleName, pattern }) {
  const headerPattern = new RegExp(
    `<Text\\s+accessibilityRole="header"\\s+style=\\{styles\\.${styleName}\\}>\\s*${pattern.source}\\s*</Text>`,
    'g',
  );
  return (source.match(headerPattern) || []).length;
}

function validateExamRouteHeaderParity() {
  let valid = true;
  let examRoute = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    examRoute = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/exam.tsx'), 'utf8');
  } catch (error) {
    reject(`app/(tabs)/exam.tsx could not be read: ${error.message}`);
    return;
  }

  const unheaderedRouteHeadings =
    examRoute.match(/<Text style=\{styles\.(?:title|sectionTitle)\}>/g) || [];
  if (unheaderedRouteHeadings.length > 0) {
    reject('exam route title and sectionTitle text must expose accessibilityRole="header"');
  }

  EXPECTED_EXAM_ROUTE_HEADERS.forEach((expectedHeader) => {
    const actualOccurrences = countExamRouteHeaderOccurrences(examRoute, expectedHeader);
    if (actualOccurrences !== expectedHeader.occurrences) {
      reject(
        `exam route header ${expectedHeader.label} appears ${actualOccurrences} times as a ${expectedHeader.styleName} header, expected ${expectedHeader.occurrences}`,
      );
      return;
    }
    examRouteHeadersValidated += actualOccurrences;
  });

  const expectedHeaderCount = EXPECTED_EXAM_ROUTE_HEADERS.reduce(
    (sum, expectedHeader) => sum + expectedHeader.occurrences,
    0,
  );
  if (valid && examRouteHeadersValidated === expectedHeaderCount) {
    examRouteHeaderParityValidated = true;
  }
}

function validateExamRouteCopyParity() {
  let valid = true;
  let examRoute = '';

  function reject(message) {
    valid = false;
    fail(message);
  }

  try {
    examRoute = fs.readFileSync(path.join(repoRoot, 'app/(tabs)/exam.tsx'), 'utf8');
  } catch (error) {
    reject(`exam route copy source could not be read: ${error.message}`);
    return;
  }

  EXPECTED_EXAM_ROUTE_COPY_SNIPPETS.forEach(([snippet, message]) => {
    if (!examRoute.includes(snippet)) reject(message);
  });

  try {
    const { activeQuestionSection, reviewSection } = getMockExamSourceCitationSections(examRoute);

    if (
      !reviewSection.includes(
        '<UHRReferenceCard language={language} reference={item.uhrReference} />',
      )
    ) {
      reject('submitted exam review must render localized UHR reference cards');
    }
    if (!reviewSection.includes('<ExplanationPanel')) {
      reject('submitted exam review must render localized explanations');
    }
    if (!reviewSection.includes('<QuestionSourceCitation')) {
      reject('submitted exam review must keep source citations');
    }
    if (
      !/<QuestionReportLink\s+language=\{language\}\s+question=\{reviewQuestion\}\s+screen="exam"\s+selectedOptionId=\{answers\[item\.questionId\]\}\s+\/>/.test(
        reviewSection,
      )
    ) {
      reject('submitted exam review must keep selected-answer report context');
    }
    if (activeQuestionSection.includes('UHRReferenceCard')) {
      reject('active unsubmitted exam questions must not render UHRReferenceCard');
    }
    if (activeQuestionSection.includes('ExplanationPanel')) {
      reject('active unsubmitted exam questions must not render ExplanationPanel');
    }
    if (!activeQuestionSection.includes('<QuestionSourceCitation')) {
      reject('active unsubmitted exam questions must keep compact source citations');
    }
    if (
      !activeQuestionSection.includes('<ProvenanceBadge language={language} question={question} />')
    ) {
      reject('active unsubmitted exam questions must keep provenance badges');
    }
    if (
      !/<QuestionReportLink\s+language=\{language\}\s+question=\{question\}\s+screen="exam"\s+\/>/.test(
        activeQuestionSection,
      )
    ) {
      reject('active unsubmitted exam questions must keep report source context');
    }
    if (
      !activeQuestionSection.includes('const isFlagged = Boolean(flaggedQuestionIds[question.id]);')
    ) {
      reject('exam flag-for-review control must derive an explicit boolean pressed state');
    }
    if (!activeQuestionSection.includes('aria-pressed={isFlagged}')) {
      reject('exam flag-for-review control must expose aria-pressed on web');
    }
    if (!activeQuestionSection.includes('accessibilityState={{ checked: isFlagged }}')) {
      reject('exam flag-for-review control must preserve native checked accessibility state');
    }
    if (
      /aria-selected=\{isFlagged\}/.test(activeQuestionSection) ||
      /accessibilityState=\{\{\s*selected:\s*(?:isFlagged|Boolean\(flaggedQuestionIds\[question\.id\]\))\s*\}\}/.test(
        activeQuestionSection,
      )
    ) {
      reject('exam flag-for-review control must use pressed toggle semantics, not selected state');
    }
  } catch (error) {
    reject(
      `exam route must keep distinct submitted-review and active-question sections: ${error.message}`,
    );
  }

  if (
    /aria-selected=\{isSelected\}/.test(examRoute) ||
    /accessibilityState=\{\{\s*selected:\s*isSelected\s*\}\}/.test(examRoute)
  ) {
    reject('active exam answer options must use checked radio semantics, not selected buttons');
  }

  const seenLabels = new Set();
  Object.entries(EXPECTED_EXAM_ROUTE_COPY_LABELS).forEach(([language, labels]) => {
    labels.forEach((label) => {
      let labelIsValid = true;
      if (!textIsTrimmedSingleSpaced(label)) {
        labelIsValid = false;
        reject(`exam route ${language} copy ${JSON.stringify(label)} must be normalized`);
      }
      if (!examRoute.includes(label)) {
        labelIsValid = false;
        reject(`exam route is missing ${language} copy ${JSON.stringify(label)}`);
      }

      const normalizedLabel = `${language}:${normalizeComparableText(label)}`;
      if (seenLabels.has(normalizedLabel)) {
        labelIsValid = false;
        reject(`exam route duplicates ${language} copy ${JSON.stringify(label)}`);
      }
      if (normalizedLabel) seenLabels.add(normalizedLabel);
      if (labelIsValid) examRouteCopyLabelsValidated += 1;
    });
  });

  const expectedLabelCount = Object.values(EXPECTED_EXAM_ROUTE_COPY_LABELS).reduce(
    (count, labels) => count + labels.length,
    0,
  );
  if (valid && examRouteCopyLabelsValidated === expectedLabelCount) {
    examRouteCopyParityValidated = true;
  }
}

function validateNativeMockExamComponentLegalCopy() {
  let valid = true;
  const swedishExamNoun = String.fromCharCode(116, 101, 110, 116, 97, 109, 101, 110);
  const bannedTerms = [
    new RegExp(`\b${['skarp', swedishExamNoun].join('\\s+')}\b`, 'i'),
    new RegExp(`\b${['starta', 'provet'].join('\\s+')}\b`, 'i'),
    new RegExp(`\b${swedishExamNoun}\b`, 'i'),
    SWEDISH_MOCK_EXAM_FORBIDDEN_COPY_PATTERN,
  ];

  function reject(message) {
    valid = false;
    fail(message);
  }

  EXPECTED_NATIVE_MOCK_EXAM_COMPONENT_COPY.forEach(({ file, snippets }) => {
    let source = '';
    try {
      source = fs.readFileSync(path.join(repoRoot, file), 'utf8');
    } catch (error) {
      reject(`${file} native mock exam copy source could not be read: ${error.message}`);
      return;
    }

    snippets.forEach(([snippet, message]) => {
      let labelIsValid = true;
      if (!source.includes(snippet)) {
        labelIsValid = false;
        reject(message);
      }
      if (labelIsValid) nativeMockExamComponentCopyLabelsValidated += 1;
    });

    bannedTerms.forEach((pattern) => {
      if (pattern.test(source)) {
        reject(
          `${file} native mock exam component copy must use clearly unofficial Swedish practice wording`,
        );
      }
    });

    NATIVE_MOCK_EXAM_UNSUPPORTED_SCORE_SOURCE_PATTERNS.forEach(({ label, pattern }) => {
      if (pattern.test(source)) {
        reject(`${file} must not expose unsupported native mock-exam ${label}`);
      }
    });
  });

  const expectedLabelCount = EXPECTED_NATIVE_MOCK_EXAM_COMPONENT_COPY.reduce(
    (count, expectedFile) => count + expectedFile.snippets.length,
    0,
  );
  if (valid && nativeMockExamComponentCopyLabelsValidated === expectedLabelCount) {
    nativeMockExamComponentLegalCopyValidated = true;
    nativeMockExamScoreSourceCopyValidated = true;
  }
}

function validateNativeMockExamLibraryAndTierCopy() {
  let valid = true;

  function reject(message) {
    valid = false;
    fail(message);
  }

  ['lib/learning/mockExamLibrary.ts', 'lib/monetization/tierComparison.ts'].forEach((file) => {
    let source = '';
    try {
      source = fs.readFileSync(path.join(repoRoot, file), 'utf8');
    } catch (error) {
      reject(`${file} native mock-exam copy source could not be read: ${error.message}`);
      return;
    }

    if (SWEDISH_MOCK_EXAM_FORBIDDEN_COPY_PATTERN.test(source)) {
      reject(`${file} Swedish mock-exam copy must use Övningsprov, not provexamen/provexamina`);
    }
  });

  const mockExamLibrary = loadTs('lib/learning/mockExamLibrary.ts');
  const library = Array.isArray(mockExamLibrary.MOCK_EXAM_LIBRARY)
    ? mockExamLibrary.MOCK_EXAM_LIBRARY
    : [];
  const labelsSv = library.map((mock) => mock.labelSv);
  const labelsEn = library.map((mock) => mock.labelEn);

  EXPECTED_NATIVE_MOCK_EXAM_LIBRARY_LABELS_SV.forEach((expectedLabel, index) => {
    if (labelsSv[index] === expectedLabel) {
      nativeMockExamLibraryLabelsValidated += 1;
      return;
    }
    reject(
      `MOCK_EXAM_LIBRARY[${index}] labelSv is ${JSON.stringify(
        labelsSv[index],
      )}, expected ${JSON.stringify(expectedLabel)}`,
    );
  });

  if (labelsSv.length !== EXPECTED_NATIVE_MOCK_EXAM_LIBRARY_LABELS_SV.length) {
    reject(
      `MOCK_EXAM_LIBRARY has ${labelsSv.length} Swedish labels, expected ${EXPECTED_NATIVE_MOCK_EXAM_LIBRARY_LABELS_SV.length}`,
    );
  }
  if (JSON.stringify(labelsEn) !== JSON.stringify(EXPECTED_NATIVE_MOCK_EXAM_LIBRARY_LABELS_EN)) {
    reject('MOCK_EXAM_LIBRARY must preserve the English Mock Exam labels');
  }

  const tierComparison = loadTs('lib/monetization/tierComparison.ts');
  const tierRows = Array.isArray(tierComparison.TIER_ROWS) ? tierComparison.TIER_ROWS : [];
  const mockExamRow = tierRows.find((row) => row.id === 'mockExams');
  if (!mockExamRow) {
    reject('TIER_ROWS must include the mockExams monetization row');
  } else if (mockExamRow.labelSv !== 'Övningsprov' || mockExamRow.labelEn !== 'Mock exams') {
    reject('TIER_ROWS mockExams row must use Övningsprov / Mock exams labels');
  } else {
    nativeMockExamTierCopyValidated = true;
  }

  if (
    valid &&
    nativeMockExamLibraryLabelsValidated === EXPECTED_NATIVE_MOCK_EXAM_LIBRARY_LABELS_SV.length
  ) {
    nativeMockExamSwedishCopyNaturalnessValidated = true;
  }
}

